아래코드를 참고해보세요 

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { createRoot } from 'react-dom/client';

/**
 * TYPES & UTILS
 */
type Point = { x: number; y: number };

// Ramer-Douglas-Peucker simplification
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  let result;
  let slope;
  let intercept;
  if (p1.x === p2.x) {
    result = Math.abs(p.x - p1.x);
  } else {
    slope = (p2.y - p1.y) / (p2.x - p1.x);
    intercept = p1.y - slope * p1.x;
    result = Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
  }
  return result;
}

function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  } else {
    return [points[0], points[points.length - 1]];
  }
}

const App: React.FC = () => {
  const [image, setImage] = useState<HTMLImageElement | null>(null);
  const [paths, setPaths] = useState<Point[][]>([]);
  const [simplifiedPaths, setSimplifiedPaths] = useState<Point[][]>([]);
  const [threshold, setThreshold] = useState(1);
  const [epsilon, setEpsilon] = useState(1.0);
  const [isProcessing, setIsProcessing] = useState(false);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const url = URL.createObjectURL(file);
    const img = new Image();
    img.onload = () => {
      setImage(img);
      traceImage(img);
    };
    img.src = url;
  };

  const traceImage = (img: HTMLImageElement) => {
    setIsProcessing(true);
    const canvas = document.createElement('canvas');
    canvas.width = img.width;
    canvas.height = img.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(img, 0, 0);
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const width = canvas.width;
    const height = canvas.height;

    // Mask to keep track of processed islands (interior and boundary)
    const visited = new Uint8Array(width * height);
    const allPaths: Point[][] = [];

    const neighbors = [
      { x: -1, y: -1 }, { x: 0, y: -1 }, { x: 1, y: -1 },
      { x: 1, y: 0 }, { x: 1, y: 1 }, { x: 0, y: 1 },
      { x: -1, y: 1 }, { x: -1, y: 0 }
    ];

    const isOpaque = (tx: number, ty: number) => {
      if (tx < 0 || tx >= width || ty < 0 || ty >= height) return false;
      return data[(ty * width + tx) * 4 + 3] >= threshold;
    };

    // Scan row by row
    for (let y = 0; y < height; y++) {
      let insideObject = false;
      for (let x = 0; x < width; x++) {
        const currentIdx = y * width + x;
        const opaque = isOpaque(x, y);

        // We only trigger tracing when we hit the LEFT edge of a NEW island
        // Not visited and is opaque
        if (opaque && visited[currentIdx] === 0) {
          const startPoint = { x, y };
          const points: Point[] = [];
          let curr = { ...startPoint };
          let prev = { x: startPoint.x - 1, y: startPoint.y };

          let iters = 0;
          const maxIters = width * height;

          while (iters < maxIters) {
            const relX = prev.x - curr.x;
            const relY = prev.y - curr.y;
            let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
            if (startIdx === -1) startIdx = 7; 

            let found = false;
            // Search clockwise
            for (let i = 1; i <= 8; i++) {
              const nextIdx = (startIdx + i) % 8;
              const nx = curr.x + neighbors[nextIdx].x;
              const ny = curr.y + neighbors[nextIdx].y;

              if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                points.push({ ...curr });
                found = true;
                break;
              }
            }

            if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
            iters++;
          }

          if (points.length > 2) {
            allPaths.push(points);

            // CRITICAL FIX: After tracing the boundary, we must mark the INTERIOR of this island as visited
            // so the scanner doesn't pick up internal pixels as "new" islands.
            // We use a simple flood fill on the visited mask for the discovered region.
            const stack = [{ x: startPoint.x, y: startPoint.y }];
            while (stack.length > 0) {
              const p = stack.pop()!;
              const pIdx = p.y * width + p.x;
              if (p.x >= 0 && p.x < width && p.y >= 0 && p.y < height && isOpaque(p.x, p.y) && visited[pIdx] === 0) {
                visited[pIdx] = 1;
                stack.push({ x: p.x + 1, y: p.y });
                stack.push({ x: p.x - 1, y: p.y });
                stack.push({ x: p.x, y: p.y + 1 });
                stack.push({ x: p.x, y: p.y - 1 });
              }
            }
          } else {
            visited[currentIdx] = 1;
          }
        }
      }
    }

    setPaths(allPaths);
    setIsProcessing(false);
  };

  useEffect(() => {
    if (paths.length > 0) {
      setSimplifiedPaths(paths.map(p => rdp(p, epsilon)));
    } else {
      setSimplifiedPaths([]);
    }
  }, [paths, epsilon]);

  useEffect(() => {
    if (!image || !canvasRef.current) return;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const container = canvas.parentElement;
    if (container) {
      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    }

    const scale = Math.min(canvas.width / image.width, canvas.height / image.height) * 0.9;
    const dx = (canvas.width - image.width * scale) / 2;
    const dy = (canvas.height - image.height * scale) / 2;

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    ctx.globalAlpha = 0.2;
    ctx.drawImage(image, dx, dy, image.width * scale, image.height * scale);
    ctx.globalAlpha = 1.0;

    simplifiedPaths.forEach((path, index) => {
      if (path.length === 0) return;

      ctx.beginPath();
      ctx.strokeStyle = index % 2 === 0 ? '#38bdf8' : '#818cf8';
      ctx.lineWidth = 2.5;
      ctx.lineJoin = 'round';
      ctx.moveTo(dx + path[0].x * scale, dy + path[0].y * scale);
      path.forEach(p => {
        ctx.lineTo(dx + p.x * scale, dy + p.y * scale);
      });
      ctx.closePath();
      ctx.stroke();

      ctx.fillStyle = '#f472b6';
      path.forEach(p => {
        ctx.beginPath();
        ctx.arc(dx + p.x * scale, dy + p.y * scale, 2, 0, Math.PI * 2);
        ctx.fill();
      });
    });
  }, [image, simplifiedPaths]);

  const copyToClipboard = () => {
    const output = simplifiedPaths.map(path => 
      path.map(p => [Number(p.x.toFixed(2)), Number(p.y.toFixed(2))])
    );
    navigator.clipboard.writeText(JSON.stringify(output));
    alert(`${simplifiedPaths.length} boundary paths copied!`);
  };

  const totalRawPoints = paths.reduce((acc, p) => acc + p.length, 0);
  const totalOptimizedPoints = simplifiedPaths.reduce((acc, p) => acc + p.length, 0);

  return (
    <div className="flex flex-col h-screen font-sans">
      <header className="p-4 border-b border-slate-700 bg-slate-900 flex justify-between items-center shrink-0">
        <div>
          <h1 className="text-xl font-bold text-sky-400">Outline Path Pro <span className="text-[10px] bg-sky-900 text-sky-200 px-2 py-0.5 rounded ml-2">v0.1.3</span></h1>
          <p className="text-xs text-slate-400">Exact perimeter coordinate extraction</p>
        </div>
        <div className="flex gap-4">
          <label className="bg-sky-600 hover:bg-sky-500 transition px-4 py-2 rounded-md cursor-pointer text-sm font-medium">
            Upload Image
            <input type="file" className="hidden" accept="image/png,image/webp" onChange={handleFileUpload} />
          </label>
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-slate-900 p-6 border-r border-slate-700 overflow-y-auto space-y-8">
          <section>
            <h2 className="text-xs uppercase tracking-widest text-slate-500 font-bold mb-4">Tracing Controls</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm text-slate-300 mb-2">Simplification (Epsilon: {epsilon})</label>
                <input 
                  type="range" min="0" max="15" step="0.1" value={epsilon} 
                  onChange={(e) => setEpsilon(parseFloat(e.target.value))}
                  className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer"
                />
              </div>
              <div>
                <label className="block text-sm text-slate-300 mb-2">Alpha Threshold: {threshold}</label>
                <input 
                  type="range" min="1" max="255" value={threshold} 
                  onChange={(e) => {
                    const val = parseInt(e.target.value);
                    setThreshold(val);
                    if (image) traceImage(image);
                  }}
                  className="w-full h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer"
                />
              </div>
            </div>
          </section>

          <section>
            <h2 className="text-xs uppercase tracking-widest text-slate-500 font-bold mb-4">Statistics</h2>
            <div className="space-y-4">
              <div className="bg-slate-800 p-3 rounded-lg text-center border border-slate-700">
                <div className="text-xs text-slate-400">Islands Detected</div>
                <div className="text-2xl font-bold text-emerald-400">{paths.length}</div>
              </div>
              <div className="grid grid-cols-2 gap-2">
                <div className="bg-slate-800 p-3 rounded-lg text-center">
                  <div className="text-[10px] text-slate-400">Boundary Points</div>
                  <div className="text-lg font-bold">{totalRawPoints}</div>
                </div>
                <div className="bg-slate-800 p-3 rounded-lg text-center">
                  <div className="text-[10px] text-slate-400">Optimized</div>
                  <div className="text-lg font-bold text-sky-400">{totalOptimizedPoints}</div>
                </div>
              </div>
            </div>
          </section>

          {simplifiedPaths.length > 0 && (
            <section className="space-y-3">
              <button 
                onClick={copyToClipboard}
                className="w-full bg-slate-800 hover:bg-slate-700 border border-slate-600 p-3 rounded-lg text-sm font-medium transition"
              >
                Copy Nested JSON
              </button>
              <div className="max-h-60 overflow-y-auto bg-black p-4 rounded-lg text-[10px] font-mono text-emerald-400 break-all border border-slate-800 scrollbar-thin">
                {JSON.stringify(simplifiedPaths.map(path => path.map(p => [Math.round(p.x), Math.round(p.y)])))}
              </div>
            </section>
          )}
        </aside>

        <section className="flex-1 canvas-container relative flex items-center justify-center p-8 overflow-hidden bg-slate-950">
          {!image && (
            <div className="text-center">
              <div className="text-6xl mb-4 text-slate-800 opacity-50">🧤</div>
              <p className="text-slate-500 italic">Tracing perimeters of disconnected objects</p>
            </div>
          )}
          <canvas ref={canvasRef} className="max-w-full max-h-full shadow-2xl" />
          {isProcessing && (
            <div className="absolute inset-0 bg-slate-950/50 flex items-center justify-center backdrop-blur-sm">
              <div className="flex flex-col items-center">
                <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-sky-500 mb-4"></div>
                <p className="text-sky-400 font-medium">Extracting perimeters...</p>
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="p-2 bg-slate-900 border-t border-slate-700 text-[10px] text-slate-500 text-center">
        Built with Gemini - Version 0.1.3 - Perimeter Tracking
      </footer>
    </div>
  );
};

const root = createRoot(document.getElementById('root')!);
root.render(<App />);

