        this.load.image('item_silhouette', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    // 배경 레이어
    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    // 실루엣 및 가이드라인 레이어
    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.pathGraphics = this.add.graphics();
    this.root.add([this.silhouetteGraphics, this.pathGraphics]);

    // UI 레이어
    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘(커서)
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    // 이미지로부터 외곽선 추출
    this.generatePathFromTexture();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      for (const node of this.targetNodes) {
        const d = Phaser.Math.Distance.Between(p.x, p.y, node.x, node.y);
        if (d < 70 * this.uiScale) {
          this.handleHit(node as any);
          break;
        }
      }
    });

    this.spawnNodes();
  }

  /**
   * 로드된 텍스처의 알파 채널을 분석하여 외곽선 경로를 생성합니다.
   */
  private generatePathFromTexture() {
    const key = 'item_silhouette';
    if (!this.textures.exists(key)) {
        // 폴백: 사각형 경로
        this.normalizedPath = [{x:0.2, y:0.2}, {x:0.8, y:0.2}, {x:0.8, y:0.8}, {x:0.2, y:0.8}, {x:0.2, y:0.2}];
        return;
    }

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50; // 알파 임계값
    };

    // 1. 첫 번째 불투명 픽셀 찾기 (시작점)
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    // 2. Moore-Neighbor Tracing (Boundary Following)
    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    // 3. 단순화 및 정규화
    const simplified = rdp(path, 1.5); // 1.5픽셀 허용 오차로 단순화

    // 중앙 정렬을 위해 범위 계산
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const rangeX = maxX - minX || 1;
    const rangeY = maxY - minY || 1;

    // 0~1 범위로 정규화 (중앙 기준 y는 -0.5 ~ 0.5)
    this.normalizedPath = simplified.map(p => ({
        x: (p.x - minX) / rangeX,
        y: ((p.y - minY) / rangeY) - 0.5
    }));
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateNodesPositions();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.normalizedPath.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const baseW = this.viewW * (isPortrait ? 0.75 : 0.6);
    const baseH = this.viewH * (isPortrait ? 0.35 : 0.5);

    this.worldPoints = this.normalizedPath.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX - (baseW / 2) + p.x * baseW,
        this.centerY + p.y * baseH
      );
    });

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath() {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 도안 실루엣
    this.silhouetteGraphics.fillStyle(0x2a1b18, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 바느질 가이드 점선
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const targetLen = Phaser.Math.Clamp(p, 0, 1) * this.totalPathLength;
    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnNodes() {
    this.targetNodes.forEach(n => n.destroy());
    this.targetNodes = [];

    const positions = [0.15, 0.4, 0.65, 0.9];
    positions.forEach(pBase => {
      const p = pBase + Phaser.Math.FloatBetween(-0.05, 0.05);
      const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981);
      (node as any).p = p;
      (node as any).hit = false;
      (node as any).missed = false;
      this.targetNodes.push(node);
      this.root.add(node);
    });
    this.updateNodesPositions();
  }

  private updateNodesPositions() {
    this.targetNodes.forEach(n => {
      const pos = this.getPathPosition((n as any).p);
      n.setPosition(pos.x, pos.y).setScale(this.uiScale);
    });
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    this.targetNodes.forEach((node: any) => {
      if (!node.hit && !node.missed && this.cursorProgress > node.p + 0.08) {
        node.missed = true;
        this.handleMiss(node.x, node.y);
      }
    });

    if (this.cursorProgress > 1.05) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnNodes();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress % 1);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
  }

  private handleHit(node: any) {
    if (node.hit || node.missed) return;
    const diff = Math.abs(this.cursorProgress - node.p);

    if (diff < 0.05) {
      node.hit = true;
      node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
      this.perfectStreak++;
      this.combo++;
      if (this.perfectStreak % 6 === 0) this.currentQuality += 1;
      this.showFeedback('PERFECT!', 0xfbbf24, node.x, node.y);
      this.createSparks(node.x, node.y, 0xfbbf24);
    } else if (diff < 0.1) {
      node.hit = true;
      node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, node.x, node.y);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(12);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘: 경로 포인트 단순화
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private targetNodes: Phaser.GameObjects.Arc[] = [];
  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private subCategoryId: string = 'SWORD';
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  // 정규화된 경로 데이터 (0~1 범위)
  private normalizedPath: Point[] = [];
  // 실제 월드 좌표 데이터
  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.subCategoryId = data.subCategoryId || 'SWORD';
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000015;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.normalizedPath = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_silhouette', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    // 배경 레이어
    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    // 실루엣 레이어
    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    // 아이템 이미지 레이어 (아웃라인 뒤에 배치)
    if (this.textures.exists('item_silhouette')) {
      this.itemSprite = this.add.image(0, 0, 'item_silhouette').setAlpha(0.15).setOrigin(0.5);
      this.root.add(this.itemSprite);
    }

    // 가이드라인 레이어
    this.pathGraphics = this.add.graphics();
    this.root.add(this.pathGraphics);

    // UI 레이어
    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘(커서) - 오리진 및 초기 방향 설정
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    // 이미지로부터 외곽선 추출
    this.generatePathFromTexture();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      for (const node of this.targetNodes) {
        const d = Phaser.Math.Distance.Between(p.x, p.y, node.x, node.y);
        if (d < 70 * this.uiScale) {
          this.handleHit(node as any);
          break;
        }
      }
    });

    this.spawnNodes();
  }

  /**
   * 로드된 텍스처의 알파 채널을 분석하여 외곽선 경로를 생성합니다.
   */
  private generatePathFromTexture() {
    const key = 'item_silhouette';
    if (!this.textures.exists(key)) {
        // 폴백: 사각형 경로
        this.normalizedPath = [{x:0.2, y:0.2}, {x:0.8, y:0.2}, {x:0.8, y:0.8}, {x:0.2, y:0.8}, {x:0.2, y:0.2}];
        return;
    }

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50; // 알파 임계값
    };

    // 1. 첫 번째 불투명 픽셀 찾기 (시작점)
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    // 2. Moore-Neighbor Tracing (Boundary Following)
    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    // 3. 단순화 및 정규화
    const simplified = rdp(path, 1.5); // 1.5픽셀 허용 오차로 단순화

    // 중앙 정렬을 위해 범위 계산
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const rangeX = maxX - minX || 1;
    const rangeY = maxY - minY || 1;

    // 0~1 범위로 정규화 (중앙 기준 y는 -0.5 ~ 0.5)
    this.normalizedPath = simplified.map(p => ({
        x: (p.x - minX) / rangeX,
        y: ((p.y - minY) / rangeY) - 0.5
    }));
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();

    // 아이템 이미지 배치 및 스케일링
    if (this.itemSprite) {
      const isPortraitPath = this.viewH > this.viewW;
      const baseW = this.viewW * (isPortraitPath ? 0.75 : 0.6);
      const baseH = this.viewH * (isPortraitPath ? 0.35 : 0.5);

      this.itemSprite.setPosition(this.centerX, this.centerY);
      // 아웃라인 영역에 맞게 이미지 크기 조절
      const scaleX = baseW / this.itemSprite.texture.getSourceImage().width;
      const scaleY = baseH / this.itemSprite.texture.getSourceImage().height;
      this.itemSprite.setScale(scaleX, scaleY);
    }

    this.updateNodesPositions();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.normalizedPath.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const baseW = this.viewW * (isPortrait ? 0.75 : 0.6);
    const baseH = this.viewH * (isPortrait ? 0.35 : 0.5);

    this.worldPoints = this.normalizedPath.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX - (baseW / 2) + p.x * baseW,
        this.centerY + p.y * baseH
      );
    });

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath() {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 도안 실루엣
    this.silhouetteGraphics.fillStyle(0x2a1b18, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 바느질 가이드 점선
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const targetLen = Phaser.Math.Clamp(p, 0, 1) * this.totalPathLength;
    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnNodes() {
    this.targetNodes.forEach(n => n.destroy());
    this.targetNodes = [];

    const positions = [0.15, 0.4, 0.65, 0.9];
    positions.forEach(pBase => {
      const p = pBase + Phaser.Math.FloatBetween(-0.05, 0.05);
      const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981);
      (node as any).p = p;
      (node as any).hit = false;
      (node as any).missed = false;
      this.targetNodes.push(node);
      this.root.add(node);
    });
    this.updateNodesPositions();
  }

  private updateNodesPositions() {
    this.targetNodes.forEach(n => {
      const pos = this.getPathPosition((n as any).p);
      n.setPosition(pos.x, pos.y).setScale(this.uiScale);
    });
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    this.targetNodes.forEach((node: any) => {
      if (!node.hit && !node.missed && this.cursorProgress > node.p + 0.08) {
        node.missed = true;
        this.handleMiss(node.x, node.y);
      }
    });

    if (this.cursorProgress > 1.05) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnNodes();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress % 1);
    this.cursor.setPosition(pos.x, pos.y);

    // 바늘의 뾰족한 부분이 경로 방향을 향하도록 (기존 +90도에서 -90도로 반전 보정)
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    // 완성도가 오를수록 아이템 이미지의 불투명도를 높임 (0.15 ~ 0.85 범위)
    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }
  }

  private handleHit(node: any) {
    if (node.hit || node.missed) return;
    const diff = Math.abs(this.cursorProgress - node.p);

    if (diff < 0.05) {
      node.hit = true;
      node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
      this.perfectStreak++;
      this.combo++;
      if (this.perfectStreak % 6 === 0) this.currentQuality += 1;
      this.showFeedback('PERFECT!', 0xfbbf24, node.x, node.y);
      this.createSparks(node.x, node.y, 0xfbbf24);
    } else if (diff < 0.1) {
      node.hit = true;
      node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, node.x, node.y);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(12);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘: 경로 포인트 단순화
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private targetNodes: Phaser.GameObjects.Arc[] = [];
  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  // 추출된 아이템 데이터 (픽셀 단위)
  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000015;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.root.add(this.pathGraphics);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();

    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      for (const node of this.targetNodes) {
        const d = Phaser.Math.Distance.Between(p.x, p.y, node.x, node.y);
        if (d < 70 * this.uiScale) {
          this.handleHit(node as any);
          break;
        }
      }
    });

    this.spawnNodes();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    // 아이템의 기하학적 중심을 0,0으로 하는 로컬 좌표계로 저장
    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateNodesPositions();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    // 가용한 최대 영역 (여백 고려)
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    // 비율 유지 Size-to-Fit 스케일 계산
    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    // 실제 월드 좌표로 변환
    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    // 이미지도 동일한 스케일과 중심점으로 정렬
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY);
        this.itemSprite.setScale(scale);
        // 아이템의 기하학적 중심을 오리진으로 설정하여 아웃라인과 완벽 일치시킴
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath() {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const targetLen = Phaser.Math.Clamp(p, 0, 1) * this.totalPathLength;
    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnNodes() {
    this.targetNodes.forEach(n => n.destroy());
    this.targetNodes = [];

    const positions = [0.15, 0.4, 0.65, 0.9];
    positions.forEach(pBase => {
      const p = pBase + Phaser.Math.FloatBetween(-0.05, 0.05);
      const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981);
      (node as any).p = p;
      (node as any).hit = false;
      (node as any).missed = false;
      this.targetNodes.push(node);
      this.root.add(node);
    });
    this.updateNodesPositions();
  }

  private updateNodesPositions() {
    this.targetNodes.forEach(n => {
      const pos = this.getPathPosition((n as any).p);
      n.setPosition(pos.x, pos.y).setScale(this.uiScale);
    });
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    this.targetNodes.forEach((node: any) => {
      if (!node.hit && !node.missed && this.cursorProgress > node.p + 0.08) {
        node.missed = true;
        this.handleMiss(node.x, node.y);
      }
    });

    if (this.cursorProgress > 1.05) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnNodes();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress % 1);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }
  }

  private handleHit(node: any) {
    if (node.hit || node.missed) return;
    const diff = Math.abs(this.cursorProgress - node.p);

    if (diff < 0.05) {
      node.hit = true;
      node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
      this.perfectStreak++;
      this.combo++;
      if (this.perfectStreak % 6 === 0) this.currentQuality += 1;
      this.showFeedback('PERFECT!', 0xfbbf24, node.x, node.y);
      this.createSparks(node.x, node.y, 0xfbbf24);
    } else if (diff < 0.1) {
      node.hit = true;
      node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, node.x, node.y);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(12);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private isUserDragging = false;
  private activeDragSegment: Interactable | null = null;
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
    this.isUserDragging = false;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      this.isUserDragging = true;

      // 탭 노드 히트 판정
      let hitAnyTap = false;
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            hitAnyTap = true;
            break;
          }
        }
      }
    });

    this.input.on('pointerup', () => {
      this.isUserDragging = false;
    });

    this.spawnInteractables();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath() {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기 (반짝이는 실선)
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.8, 6);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    // 순환 경로 대응을 위해 p % 1 처리
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables() {
    this.interactables = [];
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];

    // 난이도별 구성 다변화
    // T1: 탭 3개, 드래그 1구간
    // T2: 탭 2개, 드래그 2구간
    // T3: 드래그 위주
    const pattern = this.difficulty >= 3 ? ['DRAG', 'TAP', 'DRAG'] : this.difficulty >= 2 ? ['TAP', 'DRAG', 'TAP', 'DRAG'] : ['TAP', 'TAP', 'DRAG', 'TAP'];

    const segmentCount = pattern.length;
    const segmentSize = 0.9 / segmentCount;

    pattern.forEach((type, i) => {
        const startP = 0.05 + i * segmentSize + Phaser.Math.FloatBetween(0, 0.05);
        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: startP, hit: false, missed: false });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const endP = startP + 0.15 + (this.difficulty * 0.02);
            this.interactables.push({ type: 'DRAG', p: startP, endP: Math.min(0.98, endP), hit: false, missed: false });
        }
    });

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj, idx) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
        obj.missed = true;
        const pos = this.getPathPosition(obj.p);
        this.handleMiss(pos.x, pos.y);
      }
    });

    // 드래그 구간 로직
    this.handleDragLogic(delta);

    // 한 바퀴 완료
    if (this.cursorProgress > 1.0) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnInteractables();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }
  }

  private handleDragLogic(delta: number) {
    const p = this.cursorProgress;
    const activeSegment = this.interactables.find(obj => obj.type === 'DRAG' && p >= obj.p && p <= (obj.endP || 0));

    if (activeSegment) {
        const pointer = this.input.activePointer;
        const needlePos = { x: this.cursor.x, y: this.cursor.y };
        const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, needlePos.x, needlePos.y);

        // 드래그 판정 (누르고 있어야 하며, 바늘 근처에 있어야 함)
        const isTracking = pointer.isDown && dist < 80 * this.uiScale;

        if (isTracking) {
            this.dragPenaltyTimer = 0;
            this.cursor.setTint(0xfbbf24); // 황금색 효과
            if (time % 100 < 20) {
                this.createSparks(needlePos.x, needlePos.y, 0xfbbf24, 1);
            }
            this.perfectStreak++;
            if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
        } else {
            this.dragPenaltyTimer += delta;
            this.cursor.clearTint();
            if (this.dragPenaltyTimer > 150) { // 0.15초 이상 이탈 시 패널티
                this.dragPenaltyTimer = 0;
                this.currentQuality = Math.max(0, this.currentQuality - 1);
                this.perfectStreak = 0;
                this.combo = 0;
                this.createSparks(needlePos.x, needlePos.y, 0xef4444, 2);
                this.cameras.main.shake(50, 0.002);
            }
        }
    } else {
        this.cursor.clearTint();
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.perfectStreak += 10;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private isUserDragging = false;
  private activeDragSegment: Interactable | null = null;
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
    this.isUserDragging = false;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      this.isUserDragging = true;

      // 탭 노드 히트 판정
      let hitAnyTap = false;
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            hitAnyTap = true;
            break;
          }
        }
      }
    });

    this.input.on('pointerup', () => {
      this.isUserDragging = false;
    });

    this.spawnInteractables();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath() {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기 (반짝이는 실선)
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.8, 6);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    // 순환 경로 대응을 위해 p % 1 처리
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables() {
    this.interactables = [];
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];

    // 난이도별 구성 다변화
    // T1: 탭 3개, 드래그 1구간
    // T2: 탭 2개, 드래그 2구간
    // T3: 드래그 위주
    const pattern = this.difficulty >= 3 ? ['DRAG', 'TAP', 'DRAG'] : this.difficulty >= 2 ? ['TAP', 'DRAG', 'TAP', 'DRAG'] : ['TAP', 'TAP', 'DRAG', 'TAP'];

    const segmentCount = pattern.length;
    const segmentSize = 0.9 / segmentCount;

    pattern.forEach((type, i) => {
        const startP = 0.05 + i * segmentSize + Phaser.Math.FloatBetween(0, 0.05);
        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: startP, hit: false, missed: false });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const endP = startP + 0.15 + (this.difficulty * 0.02);
            this.interactables.push({ type: 'DRAG', p: startP, endP: Math.min(0.98, endP), hit: false, missed: false });
        }
    });

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj, idx) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
        obj.missed = true;
        const pos = this.getPathPosition(obj.p);
        this.handleMiss(pos.x, pos.y);
      }
    });

    // 드래그 구간 로직
    // FIX: Pass 'time' from update to handleDragLogic
    this.handleDragLogic(time, delta);

    // 한 바퀴 완료
    if (this.cursorProgress > 1.0) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnInteractables();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }
  }

  // FIX: Added 'time' parameter to handleDragLogic
  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    const activeSegment = this.interactables.find(obj => obj.type === 'DRAG' && p >= obj.p && p <= (obj.endP || 0));

    if (activeSegment) {
        const pointer = this.input.activePointer;
        const needlePos = { x: this.cursor.x, y: this.cursor.y };
        const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, needlePos.x, needlePos.y);

        // 드래그 판정 (누르고 있어야 하며, 바늘 근처에 있어야 함)
        const isTracking = pointer.isDown && dist < 80 * this.uiScale;

        if (isTracking) {
            this.dragPenaltyTimer = 0;
            this.cursor.setTint(0xfbbf24); // 황금색 효과
            // 'time' is now available via parameter
            if (time % 100 < 20) {
                this.createSparks(needlePos.x, needlePos.y, 0xfbbf24, 1);
            }
            this.perfectStreak++;
            if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
        } else {
            this.dragPenaltyTimer += delta;
            this.cursor.clearTint();
            if (this.dragPenaltyTimer > 150) { // 0.15초 이상 이탈 시 패널티
                this.dragPenaltyTimer = 0;
                this.currentQuality = Math.max(0, this.currentQuality - 1);
                this.perfectStreak = 0;
                this.combo = 0;
                this.createSparks(needlePos.x, needlePos.y, 0xef4444, 2);
                this.cameras.main.shake(50, 0.002);
            }
        }
    } else {
        this.cursor.clearTint();
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.perfectStreak += 10;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  moveSpeed?: number; // 구간 이동 속도
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private isUserDragging = false;
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
    this.isUserDragging = false;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      this.isUserDragging = true;

      // 탭 노드 히트 판정
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.input.on('pointerup', () => {
      this.isUserDragging = false;
    });

    this.spawnInteractables();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기 (흐르는 빛)
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP) {
            // 구간 본체 (흐르는 효과를 위해 alpha/width에 sin파 적용)
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);

            // 시작점 마커 (Emerald Ring)
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(3, 0x10b981, 1);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 10 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.4);
            this.dragPathGraphics.fillCircle(startPos.x, startPos.y, 6 * this.uiScale);

            // 종료점 마커 (Gold Ring)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(3, 0xfbbf24, 1);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 10 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.4);
            this.dragPathGraphics.fillCircle(endPos.x, endPos.y, 6 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables() {
    this.interactables = [];
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];

    const pattern = this.difficulty >= 3 ? ['DRAG', 'TAP', 'DRAG'] : this.difficulty >= 2 ? ['TAP', 'DRAG', 'TAP', 'DRAG'] : ['TAP', 'TAP', 'DRAG', 'TAP'];

    const segmentCount = pattern.length;
    const segmentSize = 0.9 / segmentCount;

    pattern.forEach((type, i) => {
        const startP = 0.05 + i * segmentSize + Phaser.Math.FloatBetween(0, 0.05);
        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: startP, hit: false, missed: false });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const length = 0.15 + (this.difficulty * 0.02);
            const endP = startP + length;
            // 이동 속도 추가 (0.00002 ~ 0.00005 사이)
            const speed = 0.00002 + (this.difficulty * 0.00001);
            this.interactables.push({ 
              type: 'DRAG', 
              p: startP, 
              endP: Math.min(0.98, endP), 
              hit: false, 
              missed: false,
              moveSpeed: speed
            });
        }
    });

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
        obj.missed = true;
        const pos = this.getPathPosition(obj.p);
        this.handleMiss(pos.x, pos.y);
      }
    });

    // 드래그 구간 로직 및 이동 처리
    this.handleDragLogic(time, delta);

    // 한 바퀴 완료
    if (this.cursorProgress > 1.0) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnInteractables();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 바늘 방향 반전: 상하를 뒤집어 뾰족한 곳이 진행 방향(+ PI/2)을 등지지 않고 향하도록(- PI / 2) 수정
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }

    // 드래그 구간이 이동하므로 가이드를 매 프레임 다시 그립니다.
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;

    // 드래그 구간 이동 처리
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && obj.moveSpeed && obj.endP) {
        obj.p += obj.moveSpeed * delta;
        obj.endP += obj.moveSpeed * delta;

        // 경로 범위를 넘어가면 순환 처리
        if (obj.p > 1.0) {
           const len = obj.endP - obj.p;
           obj.p -= 1.0;
           obj.endP = obj.p + len;
        }
      }
    });

    const activeSegment = this.interactables.find(obj => obj.type === 'DRAG' && p >= obj.p && p <= (obj.endP || 0));

    if (activeSegment) {
        const pointer = this.input.activePointer;
        const needlePos = { x: this.cursor.x, y: this.cursor.y };
        const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, needlePos.x, needlePos.y);

        // 드래그 판정 (누르고 있어야 하며, 바늘 근처에 있어야 함)
        const isTracking = pointer.isDown && dist < 80 * this.uiScale;

        if (isTracking) {
            this.dragPenaltyTimer = 0;
            this.cursor.setTint(0xfbbf24); 
            if (time % 100 < 20) {
                this.createSparks(needlePos.x, needlePos.y, 0xfbbf24, 1);
            }
            this.perfectStreak++;
            if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
        } else {
            this.dragPenaltyTimer += delta;
            this.cursor.clearTint();
            if (this.dragPenaltyTimer > 150) { // 0.15초 이상 이탈 시 패널티
                this.dragPenaltyTimer = 0;
                this.currentQuality = Math.max(0, this.currentQuality - 1);
                this.perfectStreak = 0;
                this.combo = 0;
                this.createSparks(needlePos.x, needlePos.y, 0xef4444, 2);
                this.cameras.main.shake(50, 0.002);
            }
        }
    } else {
        this.cursor.clearTint();
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.perfectStreak += 10;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  moveSpeed?: number; // 구간 이동 속도
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private isUserDragging = false;
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
    this.isUserDragging = false;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      this.isUserDragging = true;

      // 탭 노드 히트 판정
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.input.on('pointerup', () => {
      this.isUserDragging = false;
    });

    this.spawnInteractables();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기 (흐르는 빛)
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP) {
            // 구간 본체 (흐르는 효과를 위해 alpha/width에 sin파 적용)
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);

            // 시작점 마커 (Emerald Ring) - 더 선명하게 개선
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5);
            this.dragPathGraphics.fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            // 종료점 마커 (Gold Ring) - 더 선명하게 개선
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5);
            this.dragPathGraphics.fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables() {
    this.interactables = [];
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];

    const pattern = this.difficulty >= 3 ? ['DRAG', 'TAP', 'DRAG'] : this.difficulty >= 2 ? ['TAP', 'DRAG', 'TAP', 'DRAG'] : ['TAP', 'TAP', 'DRAG', 'TAP'];

    const segmentCount = pattern.length;
    const segmentSize = 0.9 / segmentCount;

    pattern.forEach((type, i) => {
        const startP = 0.05 + i * segmentSize + Phaser.Math.FloatBetween(0, 0.05);
        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: startP, hit: false, missed: false });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const length = 0.15 + (this.difficulty * 0.02);
            const endP = startP + length;
            // 이동 속도 하향 조정 (0.00001 ~ 0.000025 사이로 더 느리게)
            const speed = 0.00001 + (this.difficulty * 0.000005);
            this.interactables.push({ 
              type: 'DRAG', 
              p: startP, 
              endP: Math.min(0.98, endP), 
              hit: false, 
              missed: false,
              moveSpeed: speed
            });
        }
    });

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
        obj.missed = true;
        const pos = this.getPathPosition(obj.p);
        this.handleMiss(pos.x, pos.y);
      }
    });

    // 드래그 구간 로직 및 이동 처리
    this.handleDragLogic(time, delta);

    // 한 바퀴 완료
    if (this.cursorProgress > 1.0) {
      this.cursorProgress = 0;
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) {
        this.win();
      } else {
        this.spawnInteractables();
      }
    }

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 바늘 이미지 방향 반전: 뾰족한 부분이 진행 방향을 향하도록 수정 (+ Math.PI / 2)
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }

    // 드래그 구간이 이동하므로 가이드를 매 프레임 다시 그립니다.
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;

    // 드래그 구간 이동 처리
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && obj.moveSpeed && obj.endP) {
        obj.p += obj.moveSpeed * delta;
        obj.endP += obj.moveSpeed * delta;

        // 경로 범위를 넘어가면 순환 처리
        if (obj.p > 1.0) {
           const len = obj.endP - obj.p;
           obj.p -= 1.0;
           obj.endP = obj.p + len;
        }
      }
    });

    const activeSegment = this.interactables.find(obj => obj.type === 'DRAG' && p >= obj.p && p <= (obj.endP || 0));

    if (activeSegment) {
        const pointer = this.input.activePointer;
        const needlePos = { x: this.cursor.x, y: this.cursor.y };
        const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, needlePos.x, needlePos.y);

        // 드래그 판정 (누르고 있어야 하며, 바늘 근처에 있어야 함)
        const isTracking = pointer.isDown && dist < 80 * this.uiScale;

        if (isTracking) {
            this.dragPenaltyTimer = 0;
            this.cursor.setTint(0xfbbf24); 
            if (time % 100 < 20) {
                this.createSparks(needlePos.x, needlePos.y, 0xfbbf24, 1);
            }
            this.perfectStreak++;
            if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
        } else {
            this.dragPenaltyTimer += delta;
            this.cursor.clearTint();
            if (this.dragPenaltyTimer > 150) { // 0.15초 이상 이탈 시 패널티
                this.dragPenaltyTimer = 0;
                this.currentQuality = Math.max(0, this.currentQuality - 1);
                this.perfectStreak = 0;
                this.combo = 0;
                this.createSparks(needlePos.x, needlePos.y, 0xef4444, 2);
                this.cameras.main.shake(50, 0.002);
            }
        }
    } else {
        this.cursor.clearTint();
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.perfectStreak += 10;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xfbbf24, 1).setStrokeStyle(3, 0xffffff);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.perfectStreak = 0;
      this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);

      const node = this.tapNodeGraphics.find(n => Phaser.Math.Distance.Between(n.x, n.y, pos.x, pos.y) < 5);
      if (node) node.setFillStyle(0xe5e5e5, 0.8).setStrokeStyle(2, 0xaaaaaa);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  moveSpeed?: number; // 구간 이동 속도
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private isUserDragging = false;
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
    this.isUserDragging = false;
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;
      this.isUserDragging = true;

      // 탭 노드 히트 판정
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.input.on('pointerup', () => {
      this.isUserDragging = false;
    });

    // 시작 시 포인터 생성
    this.spawnInteractables(4);
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);

            // 시작점 마커 (Emerald Ring)
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5);
            this.dragPathGraphics.fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            // 종료점 마커 (Gold Ring)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5);
            this.dragPathGraphics.fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables(count: number = 4) {
    // 이전 그래픽들 정리 (전부 처리되었을 때 호출되므로 안전함)
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];
    this.interactables = [];

    const baseP = this.cursorProgress;

    for (let i = 0; i < count; i++) {
        // 바늘 현재 위치에서 0.15~0.85 범위 내에 순차적으로 배치
        const spawnP = baseP + 0.15 + (i * 0.2) + Phaser.Math.FloatBetween(-0.05, 0.05);
        const type = (i % 2 === 0) ? 'TAP' : 'DRAG';

        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: spawnP % 1.0, hit: false, missed: false });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const length = 0.12 + (this.difficulty * 0.015);
            const speed = 0.00001 + (this.difficulty * 0.000005);
            this.interactables.push({ 
              type: 'DRAG', 
              p: spawnP % 1.0, 
              endP: (spawnP + length) % 1.0, 
              hit: false, 
              missed: false,
              moveSpeed: speed
            });
        }
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;
    if (this.cursorProgress >= 1.0) this.cursorProgress %= 1.0;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const dist = this.getShortestPDiff(this.cursorProgress, obj.p);
          if (dist < -0.1) { // 이미 지나친 경우
              obj.missed = true;
              const pos = this.getPathPosition(obj.p);
              this.handleMiss(pos.x, pos.y);
          }
      }
    });

    // 드래그 구간 로직 및 이동 처리
    this.handleDragLogic(time, delta);

    // 모든 포인터가 처리되었는지 확인
    const activeInteractions = this.interactables.filter(obj => !obj.hit && !obj.missed);
    if (activeInteractions.length === 0) {
        this.spawnInteractables(4);
    }

    // 바늘 동기화
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }

    this.drawGuidePath(time);
  }

  private getShortestPDiff(p1: number, p2: number): number {
    let diff = p1 - p2;
    if (diff > 0.5) diff -= 1.0;
    if (diff < -0.5) diff += 1.0;
    return diff;
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;

    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && obj.moveSpeed && obj.endP && !obj.hit && !obj.missed) {
        obj.p = (obj.p + obj.moveSpeed * delta) % 1.0;
        obj.endP = (obj.endP + obj.moveSpeed * delta) % 1.0;

        // 드래그 완료 여부 체크 (끝점을 이미 지났을 때)
        const distToEnd = this.getShortestPDiff(p, obj.endP);
        if (distToEnd > 0) {
            obj.hit = true;
            this.addProgress(5); // 드래그 완료 시 진행도 상승
            const pos = this.getPathPosition(obj.endP);
            this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
            this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
        }
      }
    });

    const activeSegment = this.interactables.find(obj => obj.type === 'DRAG' && !obj.hit && !obj.missed && this.isInsideSegment(p, obj.p, obj.endP!));

    if (activeSegment) {
        const pointer = this.input.activePointer;
        const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
        const isTracking = pointer.isDown && dist < 80 * this.uiScale;

        if (isTracking) {
            this.dragPenaltyTimer = 0;
            this.cursor.setTint(0xfbbf24); 
            if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            this.perfectStreak++;
            if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
        } else {
            this.dragPenaltyTimer += delta;
            this.cursor.clearTint();
            if (this.dragPenaltyTimer > 150) {
                this.dragPenaltyTimer = 0;
                this.currentQuality = Math.max(0, this.currentQuality - 1);
                this.perfectStreak = 0;
                this.combo = 0;
                this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2);
                this.cameras.main.shake(50, 0.002);
            }
        }
    } else {
        this.cursor.clearTint();
    }
  }

  private isInsideSegment(p: number, start: number, end: number): boolean {
      if (start <= end) return p >= start && p <= end;
      return p >= start || p <= end;
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.getShortestPDiff(this.cursorProgress, obj.p));
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.addProgress(5);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.combo = 0;
      this.addProgress(3);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.cameras.main.shake(100, 0.005);
  }

  private addProgress(amount: number) {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + amount);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) this.win();
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  moveSpeed?: number; // 구간 이동 속도
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private perfectStreak = 0;
  private combo = 0;
  private isFinished = false;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  // 드래그 판정 상태
  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000018;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.perfectStreak = 0;
    this.combo = 0;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      // 탭 노드 히트 판정
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    // 시작 시 포인터 생성
    this.spawnInteractables(4);
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };

    const neighbors = [
        {x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1},
        {x:1, y:0}, {x:1, y:1}, {x:0, y:1},
        {x:-1, y:1}, {x:-1, y:0}
    ];

    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;

        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);

    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });

    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;

    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);

    const scale = Math.min(
        maxAreaW / this.itemInternalData.width,
        maxAreaH / this.itemInternalData.height
    );

    this.worldPoints = this.itemInternalData.points.map(p => {
      return new Phaser.Math.Vector2(
        this.centerX + (p.x * scale),
        this.centerY + (p.y * scale)
      );
    });

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(
            this.itemInternalData.centerX / this.itemInternalData.texW,
            this.itemInternalData.centerY / this.itemInternalData.texH
        );
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();

    if (this.worldPoints.length < 2) return;

    // 1. 실루엣
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) {
      this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    }
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    // 2. 기본 바느질 경로 (점선)
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10;
    const gapSize = 8;

    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i];
      const end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end);
      const angle = Phaser.Math.Angle.BetweenPoints(start, end);

      let currentDist = 0;
      let draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) {
          this.pathGraphics.lineBetween(
            start.x + Math.cos(angle) * currentDist,
            start.y + Math.sin(angle) * currentDist,
            start.x + Math.cos(angle) * nextDist,
            start.y + Math.sin(angle) * nextDist
          );
        }
        currentDist = nextDist;
        draw = !draw;
      }
    }

    // 3. 드래그 구간 그리기
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);

            // 시작점 마커 (Emerald Ring)
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5);
            this.dragPathGraphics.fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            // 종료점 마커 (Gold Ring)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5);
            this.dragPathGraphics.strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5);
            this.dragPathGraphics.fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    const steps = 40;
    const stepSize = (endP - startP) / steps;

    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;

    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) {
      seg++;
    }

    const segStart = this.cumulativeLengths[seg];
    const segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);

    const p1 = this.worldPoints[seg];
    const p2 = this.worldPoints[seg + 1];

    const x = Phaser.Math.Linear(p1.x, p2.x, t);
    const y = Phaser.Math.Linear(p1.y, p2.y, t);
    const angle = Phaser.Math.Angle.BetweenPoints(p1, p2);

    return { x, y, angle };
  }

  private spawnInteractables(count: number = 4) {
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];
    this.interactables = [];

    // 바늘 현재 위치에서 충분히 먼 지점(최소 0.2 오프셋)부터 배치 시작
    const baseP = this.cursorProgress;

    for (let i = 0; i < count; i++) {
        const spawnP = baseP + 0.2 + (i * 0.2) + Phaser.Math.FloatBetween(-0.02, 0.02);
        const type = (i % 2 === 0) ? 'TAP' : 'DRAG';

        if (type === 'TAP') {
            this.interactables.push({ type: 'TAP', p: spawnP % 1.0, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
            const node = this.add.circle(0, 0, 18, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
            this.tapNodeGraphics.push(node);
            this.root.add(node);
        } else {
            const length = 0.12 + (this.difficulty * 0.015);
            const speed = 0.00001 + (this.difficulty * 0.000005);
            this.interactables.push({ 
              type: 'DRAG', 
              p: spawnP % 1.0, 
              endP: (spawnP + length) % 1.0, 
              hit: false, 
              missed: false,
              moveSpeed: speed,
              dragSuccessTicks: 0,
              totalTicksInRange: 0
            });
        }
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y).setScale(this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;
    if (this.cursorProgress >= 1.0) this.cursorProgress %= 1.0;

    // 탭 노드 미스 체크: 바늘이 노드 위치를 일정 거리 이상(0.08) 지나쳤을 때
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const diff = this.getShortestPDiff(this.cursorProgress, obj.p);
          if (diff > 0.08) { 
              obj.missed = true;
              const pos = this.getPathPosition(obj.p);
              this.handleMiss(pos.x, pos.y);
          }
      }
    });

    // 드래그 구간 로직 및 이동 처리
    this.handleDragLogic(time, delta);

    // 모든 포인터가 처리되었는지 확인
    const activeInteractions = this.interactables.filter(obj => !obj.hit && !obj.missed);
    if (activeInteractions.length === 0) {
        this.spawnInteractables(4);
    }

    // 바늘 동기화
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }

    this.drawGuidePath(time);
  }

  private getShortestPDiff(p1: number, p2: number): number {
    let diff = p1 - p2;
    if (diff > 0.5) diff -= 1.0;
    if (diff < -0.5) diff += 1.0;
    return diff;
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;

    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        // 구간 자체의 이동 속도 반영
        if (obj.moveSpeed) {
            obj.p = (obj.p + obj.moveSpeed * delta) % 1.0;
            obj.endP = (obj.endP! + obj.moveSpeed * delta) % 1.0;
        }

        // 바늘이 구간 내에 있는지 확인
        const inside = this.isInsideSegment(p, obj.p, obj.endP!);
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            const isTracking = pointer.isDown && dist < 80 * this.uiScale;

            if (isTracking) {
                obj.dragSuccessTicks += delta;
                this.dragPenaltyTimer = 0;
                this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                this.perfectStreak++;
                if (this.perfectStreak % 30 === 0) this.currentQuality = Math.min(120, this.currentQuality + 1);
            } else {
                this.dragPenaltyTimer += delta;
                this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0;
                    this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.perfectStreak = 0;
                    this.combo = 0;
                    this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2);
                    this.cameras.main.shake(50, 0.002);
                }
            }
        }

        // 구간 종료 체크 (바늘이 구간 끝점을 지났을 때)
        const distToEnd = this.getShortestPDiff(p, obj.endP!);
        if (distToEnd > 0.02 && obj.totalTicksInRange > 50) {
            // 조작 품질 평가: 전체 체류 시간의 50% 이상 누르고 있었어야 성공
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.5) {
                obj.hit = true;
                this.addProgress(5);
                const exitPos = this.getPathPosition(obj.endP!);
                this.showFeedback('PERFECT!', 0xfbbf24, exitPos.x, exitPos.y);
                this.createSparks(exitPos.x, exitPos.y, 0xfbbf24, 15);
            } else {
                obj.missed = true;
                const exitPos = this.getPathPosition(obj.endP!);
                this.handleMiss(exitPos.x, exitPos.y);
            }
        }
      }
    });

    // 드래그 중이 아닐 때 틴트 초기화
    const isAnyActive = this.interactables.some(obj => obj.type === 'DRAG' && !obj.hit && !obj.missed && this.isInsideSegment(p, obj.p, obj.endP!));
    if (!isAnyActive) {
        this.cursor.clearTint();
    }
  }

  private isInsideSegment(p: number, start: number, end: number): boolean {
      if (start <= end) return p >= start && p <= end;
      return p >= start || p <= end;
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.getShortestPDiff(this.cursorProgress, obj.p));
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.05) {
      obj.hit = true;
      this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 1);
      this.addProgress(5);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);
    } else if (diff < 0.1) {
      obj.hit = true;
      this.combo = 0;
      this.addProgress(3);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xffffff, 5);
    }
  }

  private handleMiss(x: number, y: number) {
    this.perfectStreak = 0;
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); // 실패 시 붉은 불꽃
    this.cameras.main.shake(100, 0.005);
  }

  private addProgress(amount: number) {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + amount);
      this.updateProgressBar();
      if (this.confirmedProgress >= 100) this.win();
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', {
      lifespan: 500,
      speed: { min: 100, max: 250 },
      scale: { start: 0.5, end: 0 },
      alpha: { start: 1, end: 0 },
      blendMode: 'ADD',
      tint: color,
      gravityY: 400
    });
    this.root.add(emitter);
    emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });

    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: 1,
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1200, () => {
          if (this.onComplete) this.onComplete(this.currentQuality);
        });
      }
    });
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];
  private tapNodeGraphics: Phaser.GameObjects.Arc[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1; // 1 to 4

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000015;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      // 탭 노드 히트 판정
      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width;
    canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data;
    const w = canvas.width;
    const h = canvas.height;

    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };

    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) {
            if (isOpaque(x, y)) {
                startPoint = { x, y };
                break outer;
            }
        }
    }

    if (!startPoint) return;

    const path: Point[] = [];
    let curr = { ...startPoint };
    let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x;
        const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8;
            const nx = curr.x + neighbors[idx].x;
            const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) {
                prev = { ...curr };
                curr = { x: nx, y: ny };
                path.push({ ...curr });
                found = true;
                break;
            }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }

    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x;
        if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y;
        if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1;
    const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2;
    const itemCY = (minY + maxY) / 2;

    this.itemInternalData = {
        points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })),
        width: itemW,
        height: itemH,
        centerX: itemCX,
        centerY: itemCY,
        texW: w,
        texH: h
    };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;

    this.viewW = w;
    this.viewH = h;
    this.centerX = w / 2;
    this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);

    this.bgImage.setPosition(this.centerX, this.centerY);
    this.bgImage.setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));

    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);

    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);

    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));

    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale);
        this.itemSprite.setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }

    this.cumulativeLengths = [0];
    let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear();
    this.pathGraphics.clear();
    this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;

    this.silhouetteGraphics.fillStyle(0x1a0b08, 1);
    this.silhouetteGraphics.beginPath();
    this.silhouetteGraphics.moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath();
    this.silhouetteGraphics.fillPath();

    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize;
        const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }

    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);

            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60;
    const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP);
    graphics.beginPath();
    graphics.moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) {
        const pos = this.getPathPosition(startP + stepSize * i);
        graphics.lineTo(pos.x, pos.y);
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0;
    while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.tapNodeGraphics.forEach(n => n.destroy());
    this.tapNodeGraphics = [];
    this.interactables = [];

    if (this.currentPhase === 1) {
        // Phase 1: 4 TAPs
        const positions = [0.25, 0.5, 0.75, 0.95];
        positions.forEach(p => this.addTap(p));
    } else if (this.currentPhase === 2) {
        // Phase 2: 1 Long DRAG
        this.addDrag(0.05, 0.95);
    } else if (this.currentPhase === 3) {
        // Phase 3: 8 TAPs
        const positions = [0.1, 0.2, 0.35, 0.5, 0.65, 0.75, 0.85, 0.95];
        positions.forEach(p => this.addTap(p));
    } else if (this.currentPhase === 4) {
        // Phase 4: 1 Long DRAG
        this.addDrag(0.05, 0.95);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.tapNodeGraphics.push(node);
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    let tapIdx = 0;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP') {
        const pos = this.getPathPosition(obj.p);
        const node = this.tapNodeGraphics[tapIdx++];
        if (node) node.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;

    this.cursorProgress += this.cursorSpeed * delta;

    // 탭 노드 미스 체크
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true;
          const pos = this.getPathPosition(obj.p);
          this.handleMiss(pos.x, pos.y);
      }
    });

    this.handleDragLogic(time, delta);

    // 페이즈 완료 체크 (한 바퀴 완료)
    if (this.cursorProgress >= 1.0) {
        this.finishPhase();
    }

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle + Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));

    if (this.itemSprite) {
      const targetAlpha = 0.15 + (this.confirmedProgress / 100) * 0.7;
      this.itemSprite.setAlpha(targetAlpha);
    }

    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            const isTracking = pointer.isDown && dist < 100 * this.uiScale;
            if (isTracking) {
                obj.dragSuccessTicks += delta;
                this.dragPenaltyTimer = 0;
                this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta;
                this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0;
                    this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0;
                    this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2);
                    this.cameras.main.shake(50, 0.001);
                }
            }
        }
        const hasPassed = p > obj.endP! + 0.02;
        if (hasPassed && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true;
                this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y);
                this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true;
                this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true;
                this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.05) {
      obj.hit = true; this.combo++;
      this.currentQuality = Math.min(120, this.currentQuality + 2);
      this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xfbbf24, 12);
    } else if (diff < 0.1) {
      obj.hit = true; this.combo = 0;
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
      this.createSparks(pos.x, pos.y, 0xffffff, 5);
    }
  }

  private handleMiss(x: number, y: number) {
    this.combo = 0;
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8);
    this.cameras.main.shake(100, 0.005);
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25);
      this.updateProgressBar();
      if (this.currentPhase < 4) {
          this.startPhase(this.currentPhase + 1);
      } else {
          this.win();
      }
  }

  private updateProgressBar() {
    const w = (this.confirmedProgress / 100) * this.progBg.width;
    this.progressBar.width = Math.max(0.1, w);
  }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb);
    this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) {
      this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 });
    }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK';
    if (q >= 100) return 'PRISTINE';
    if (q >= 90) return 'SUPERIOR';
    if (q >= 80) return 'FINE';
    if (q >= 70) return 'STANDARD';
    if (q >= 60) return 'RUSTIC';
    return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  private win() {
    this.isFinished = true;
    this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask);
    this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt);
    this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00015;
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000015;
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        // 구획별 랜덤 생성
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        // 드래그 구간 랜덤화
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y).setRotation(pos.angle + Math.PI / 2);
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      // 노드 파괴 애니메이션
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; // 감속 조정
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    // 바늘 속도 대폭 하향 (기존 0.00012+... -> 0.00008+...)
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.8).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        // 구획별 랜덤 생성
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        // 드래그 구간 랜덤화
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y).setRotation(pos.angle + Math.PI / 2);
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      // 노드 파괴 애니메이션
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘 중심점(Origin)을 뾰족한 끝부분(이미지 상단)으로 변경: (0.5, 0.2)
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.2).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.hit && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        // 구획별 랜덤 생성
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        // 드래그 구간 랜덤화
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    // 바늘 위치 및 회전 업데이트
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 회전 조정: 이미지 바늘코가 위(Up)를 향하고 있으므로, 
    // 진행 방향(pos.angle)에 맞춰 회전하되 몸통이 뒤따라가도록 -Math.PI / 2를 적용합니다.
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      // 노드 파괴 애니메이션
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘 중심점(Origin)을 뾰족한 끝부분(이미지 상단)으로 변경: (0.5, 0.2)
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.2).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            const p = this.cursorProgress;

            if (obj.hit) {
                // 이미 성공한 드래그: 전체 황금색
                this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
            } else if (p > obj.p && p <= obj.endP) {
                // 현재 진행 중인 드래그: 지나온 구간(황금색) + 남은 구간(녹색 가이드)
                this.drawPathSegment(obj.p, p, this.dragPathGraphics, 0xfbbf24, 1.0, 8); // Traced part
                this.drawPathSegment(p, obj.endP, this.dragPathGraphics, 0x10b981, 0.5, 5); // Remaining part
            } else {
                // 시작 전인 드래그: 전체 녹색 가이드
                const pulse = (Math.sin(time * 0.01) + 1) / 2;
                this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);
            }

            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        // 구획별 랜덤 생성
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        // 드래그 구간 랜덤화
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    // 바늘 위치 및 회전 업데이트
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 회전 조정: 이미지 바늘코가 위(Up)를 향하고 있으므로, 
    // 진행 방향(pos.angle)에 맞춰 회전하되 몸통이 뒤따라가도록 -Math.PI / 2를 적용합니다.
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      // 노드 파괴 애니메이션
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘 중심점(Origin)을 뾰족한 끝부분(이미지 하단)으로 변경: (0.5, 0.98)
    // 이미지의 상단이 바늘코(Eye)이므로, 하단을 고정점으로 잡아야 끝이 경로에 닿습니다.
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            const p = this.cursorProgress;

            if (obj.hit) {
                // 이미 성공한 드래그: 전체 황금색
                this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
            } else if (p > obj.p && p <= obj.endP) {
                // 현재 진행 중인 드래그: 지나온 구간(황금색) + 남은 구간(녹색 가이드)
                this.drawPathSegment(obj.p, p, this.dragPathGraphics, 0xfbbf24, 1.0, 8); // Traced part
                this.drawPathSegment(p, obj.endP, this.dragPathGraphics, 0x10b981, 0.5, 5); // Remaining part
            } else {
                // 시작 전인 드래그: 전체 녹색 가이드
                const pulse = (Math.sin(time * 0.01) + 1) / 2;
                this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.7 + pulse * 0.2, 5 + pulse * 2);
            }

            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(startPos.x, startPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.lineStyle(1, 0xffffff, 0.5).strokeCircle(endPos.x, endPos.y, 16 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        // 구획별 랜덤 생성
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        // 드래그 구간 랜덤화
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0 });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    // 바늘 위치 및 회전 업데이트
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 회전 조정: 이미지 바늘코(Eye)가 상단(0.0)에 있으므로, 
    // 진행 방향(pos.angle)에 맞춰 회전하되 바늘코가 뒤따라가도록 -Math.PI / 2를 적용합니다.
    // Origin이 0.98(바늘 끝)이므로 이제 바늘 끝이 경로에 고정된 채 몸체만 회전합니다.
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      // 노드 파괴 애니메이션
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 바늘 중심점(Origin)을 하단 뾰족한 끝부분으로 유지: (0.5, 0.98)
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            // 1. 기본 가이드 라인 (연한 녹색)
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            // 2. 실제로 터치하여 통과한 구간들 (황금색)
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);

            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];

    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }

    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [] });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    this.cursor.setRotation(pos.angle - Math.PI / 2);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 사용자가 터치하고 있고 바늘 끝 근처인 경우에만 트레이싱 세그먼트 업데이트
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);

                // 세그먼트 기록 로직: 마지막 세그먼트가 현재 위치와 인접하면 연장, 아니면 새로 추가
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) {
                    lastSeg.end = p;
                } else {
                    obj.tracedSegments.push({ start: p, end: p });
                }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }

        // 드래그 종료 지점 통과 후 판정
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({
              targets: target,
              scale: this.uiScale * 2,
              alpha: 0,
              duration: 300,
              ease: 'Cubic.out',
              onComplete: () => target.destroy()
          });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) {
        this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() });
    }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [] });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 각도 보간(Lerp) 적용: 세그먼트 전환 시 발생하는 '턱' 하는 떨림을 제거합니다.
    const targetRotation = pos.angle - Math.PI / 2;
    this.cursor.rotation = Phaser.Math.Angle.Lerp(this.cursor.rotation, targetRotation, 0.15);

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            const pulse = (Math.sin(time * 0.01) + 1) / 2;
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            const startPos = this.getPathPosition(obj.p);
            this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [] });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // Phaser.Math.Angle.Lerp가 존재하지 않으므로 ShortestBetween를 사용하여 각도 보간을 수행합니다.
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            // 사용자가 이미 드래그를 시작했는지 확인 (시작점 포함 세그먼트 존재 여부)
            const hasStarted = obj.tracedSegments && obj.tracedSegments.some(seg => seg.start <= obj.p + 0.01);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링: 드래그가 시작되지 않았을 때만 표시
            if (!hasStarted && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링: 항상 황금색으로 유지 (성공 시까지 목표 제공)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [] });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // Phaser.Math.Angle.Lerp가 존재하지 않으므로 ShortestBetween를 사용하여 각도 보간을 수행합니다.
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          const nodePos = this.getPathPosition(obj.p);
          const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            // dragSuccessTicks가 0보다 크면 사용자가 터치를 시작한 것으로 간주합니다.
            const hasStarted = obj.dragSuccessTicks > 0;

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링: 터치가 성공적으로 시작되지 않았을 때만 표시
            if (!hasStarted && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링: 항상 황금색으로 유지 (목표 지점)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [] });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // Phaser.Math.Angle.Lerp가 존재하지 않으므로 ShortestBetween를 사용하여 각도 보간을 수행합니다.
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 지점 터치 성공 여부
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정 (1, 3페이즈)
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 판정 (2페이즈 가이드 링 제거용)
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 거리가 가깝고 바늘 위치가 시작점 근처(0.1 범위 내)일 때 터치 인정
            if (d < 60 * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                this.createSparks(nodePos.x, nodePos.y, 0x10b981, 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            // startHit가 되었거나 이미 드래그 포인트가 누적되었다면 시작 지점 링을 숨깁니다.
            const hasStarted = obj.startHit || obj.dragSuccessTicks > 0;

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링: 터치가 성공적으로 시작되지 않았을 때만 표시
            if (!hasStarted && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링: 항상 황금색으로 유지 (목표 지점)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && !obj.hit && !obj.missed && this.cursorProgress > obj.p + 0.08) {
          obj.missed = true; const pos = this.getPathPosition(obj.p); this.handleMiss(pos.x, pos.y, obj);
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // Phaser.Math.Angle.Lerp가 존재하지 않으므로 ShortestBetween를 사용하여 각도 보간을 수행합니다.
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; 
                obj.startHit = true; // 터치 유지 중이라면 시작 지점 터치 성공으로 간주
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.8) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00008 + data.difficulty * 0.00001; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 60 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            if (d < 60 * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.startHitPerfect = diff < 0.05;

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링: 터치가 성공적으로 수행되기 전까지만 표시
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링: 항상 황금색으로 유지 (목표 지점)
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // TAP 또는 DRAG 시작을 놓친 경우
          if (this.cursorProgress > obj.p + 0.08) {
              if (obj.type === 'TAP' || (obj.type === 'DRAG' && !obj.startHit)) {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // startHit가 성공한 경우에만 드래그 가점 인정
            if (obj.startHit && pointer.isDown && dist < 100 * this.uiScale) {
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                // 터치를 뗐을 때의 페널티
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(50, 0.001);
                }
            } else {
                // startHit를 하지 않은 경우 바늘 색상 유지 및 가점 없음
                this.cursor.clearTint();
            }
        }

        // 드래그 구간 종료 판정
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 80% 이상 AND 시작 터치가 PERFECT였음
            if (ratio > 0.8 && obj.startHitPerfect) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.5) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(100, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; // 기본 속도 약간 상향
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정 (엄격한 거리 40 적용)
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 40 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정 (엄격한 거리 40, 오차 0.06 적용)
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            if (d < 40 * this.uiScale && diff < 0.06) {
                obj.startHit = true;
                obj.startHitPerfect = diff < 0.035; // 매우 정밀해야 PERFECT

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 엄격화: 0.08 -> 0.05
          if (this.cursorProgress > obj.p + 0.05) {
              if (obj.type === 'TAP' || (obj.type === 'DRAG' && !obj.startHit)) {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 엄격화: 100 -> 55
            if (obj.startHit && pointer.isDown && dist < 55 * this.uiScale) {
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                // 페널티 가중치 상향: 200ms -> 120ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 120) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.002);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // STRICT RULE: 시작이 PERFECT가 아니면 최종도 PERFECT일 수 없음
            if (ratio > 0.85 && obj.startHitPerfect) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 2.5);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                obj.hit = true; this.currentQuality = Math.max(0, this.currentQuality - 2);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    // TAP 판정 오차 축소: 0.1 -> 0.06
    if (diff < 0.06) {
      obj.hit = true;
      const isPerfect = diff < 0.035;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 2);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.008);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 45 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 시작 지점 타이밍 오차 범위 내 터치 시
            if (d < 50 * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;
                obj.startHitPerfect = diff < 0.04; 

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링 (터치가 성공적으로 수행되기 전까지만 표시)
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 지점 통과 체크
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  // 드래그 시작 터치를 놓친 경우: 즉시 실패 처리하지 않고 플래그만 설정
                  obj.missedStart = true;
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 완화: 55 -> 80
            if (pointer.isDown && dist < 80 * this.uiScale) {
                // 시작 터치를 놓쳤더라도 중간에 잡으면 추적 시작
                if (!obj.startHit) obj.startHit = true;

                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                // 페널티 가중치 완화: 120ms -> 200ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 85% 이상 AND 시작 터치가 PERFECT였음 AND 시작을 놓치지 않음
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                // 시작을 놓쳤거나 완벽하지 않아도 어느 정도 유지했다면 GOOD
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                // 유지율이 너무 낮으면 MISS
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 45 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 시작 지점 타이밍 오차 범위 내 터치 시
            if (d < 50 * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;
                obj.startHitPerfect = diff < 0.04; 

                // 버그 수정: 시작 지점(obj.p)부터 현재 바늘 위치까지의 세그먼트를 즉시 생성하여 경로 색상 단절 방지
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링 (터치가 성공적으로 수행되기 전까지만 표시)
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                this.dragPathGraphics.lineStyle(4, 0x10b981, 1).strokeCircle(startPos.x, startPos.y, 14 * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, 0.5).fillCircle(startPos.x, startPos.y, 8 * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 지점 통과 체크
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  // 드래그 시작 터치를 놓친 경우: 즉시 실패 처리하지 않고 플래그만 설정
                  obj.missedStart = true;
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 완화: 55 -> 80
            if (pointer.isDown && dist < 80 * this.uiScale) {
                // 시작 터치를 놓쳤더라도 중간에 잡으면 추적 시작
                if (!obj.startHit) {
                    obj.startHit = true;
                    // 중간에 잡은 경우 해당 지점부터 추적 시작
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }

                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);

                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { 
                    lastSeg.end = p; 
                } else { 
                    obj.tracedSegments.push({ start: p, end: p }); 
                }
            } else if (obj.startHit) {
                // 페널티 가중치 완화: 120ms -> 200ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 85% 이상 AND 시작 터치가 PERFECT였음 AND 시작을 놓치지 않음
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                // 시작을 놓쳤거나 완벽하지 않아도 어느 정도 유지했다면 GOOD
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                // 유지율이 너무 낮으면 MISS
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          if (d < 45 * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 시작 링 타입에 따른 가변 판정 범위 설정
            let hitRadius = 55;
            if (obj.ringType === 'NARROW') hitRadius = 35;
            else if (obj.ringType === 'MEDIUM') hitRadius = 55;
            else if (obj.ringType === 'WIDE') hitRadius = 80;

            // 시작 지점 타이밍 오차 범위 내 터치 시
            if (d < hitRadius * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;

                // 링 타입별 정밀도 보정: 좁은 링은 정밀도가 조금 낮아도 PERFECT 허용
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.06 : 0.04;
                obj.startHitPerfect = diff < perfectThreshold; 

                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링 (유형별 크기 적용)
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                let ringRadius = 20;
                let strokeW = 4;
                let alpha = 1;

                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }

                this.dragPathGraphics.lineStyle(strokeW, 0x10b981, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const node = this.add.circle(0, 0, 18 * this.uiScale, 0x10b981, 0.3).setStrokeStyle(3, 0x10b981).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    // 3가지 링 크기 중 하나를 무작위로 선택
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];

    this.interactables.push({ 
        type: 'DRAG', p: start, endP: end, hit: false, missed: false, 
        dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], 
        startHit: false, startHitPerfect: false, missedStart: false,
        ringType 
    });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 지점 통과 체크
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  // 드래그 시작 터치를 놓친 경우: 즉시 실패 처리하지 않고 플래그만 설정
                  obj.missedStart = true;
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 완화: 55 -> 80
            if (pointer.isDown && dist < 80 * this.uiScale) {
                // 시작 터치를 놓쳤더라도 중간에 잡으면 추적 시작
                if (!obj.startHit) {
                    obj.startHit = true;
                    // 중간에 잡은 경우 해당 지점부터 추적 시작
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }

                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);

                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { 
                    lastSeg.end = p; 
                } else { 
                    obj.tracedSegments.push({ start: p, end: p }); 
                }
            } else if (obj.startHit) {
                // 페널티 가중치 완화: 120ms -> 200ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 85% 이상 AND 시작 터치가 PERFECT였음 AND 시작을 놓치지 않음
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                // 시작을 놓쳤거나 완벽하지 않아도 어느 정도 유지했다면 GOOD
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                // 유지율이 너무 낮으면 MISS
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정 (무작위 크기에 따른 가변 범위 적용)
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 55;
          if (obj.ringType === 'NARROW') tapHitRadius = 35;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 55;
          else if (obj.ringType === 'WIDE') tapHitRadius = 80;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 시작 링 타입에 따른 가변 판정 범위 설정
            let hitRadius = 55;
            if (obj.ringType === 'NARROW') hitRadius = 35;
            else if (obj.ringType === 'MEDIUM') hitRadius = 55;
            else if (obj.ringType === 'WIDE') hitRadius = 80;

            // 시작 지점 타이밍 오차 범위 내 터치 시
            if (d < hitRadius * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;

                // 링 타입별 정밀도 보정
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.06 : 0.04;
                obj.startHitPerfect = diff < perfectThreshold; 

                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : 0xe5e5e5;

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링 (유형별 크기 적용)
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                let ringRadius = 20;
                let strokeW = 4;
                let alpha = 1;

                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }

                this.dragPathGraphics.lineStyle(strokeW, 0x10b981, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(0x10b981, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    // 탭 페이즈(1, 3)의 노드들을 3가지 크기로 무작위 설정
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];

    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const node = this.add.circle(0, 0, ringRadius * this.uiScale, 0x10b981, 0.3)
        .setStrokeStyle(3, 0x10b981)
        .setDepth(8);

    this.interactables.push({ 
        type: 'TAP', p, hit: false, missed: false, 
        dragSuccessTicks: 0, totalTicksInRange: 0, 
        graphic: node,
        ringType 
    });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    // 드래그 페이즈(2, 4)의 시작점은 중간 크기로 고정
    const ringType: RingType = 'MEDIUM';

    this.interactables.push({ 
        type: 'DRAG', p: start, endP: end, hit: false, missed: false, 
        dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], 
        startHit: false, startHitPerfect: false, missedStart: false,
        ringType 
    });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);

        // 리사이즈 시 반경 업데이트
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 지점 통과 체크
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  // 드래그 시작 터치를 놓친 경우: 즉시 실패 처리하지 않고 플래그만 설정
                  obj.missedStart = true;
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 완화: 55 -> 80
            if (pointer.isDown && dist < 80 * this.uiScale) {
                // 시작 터치를 놓쳤더라도 중간에 잡으면 추적 시작
                if (!obj.startHit) {
                    obj.startHit = true;
                    // 중간에 잡은 경우 해당 지점부터 추적 시작
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }

                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);

                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { 
                    lastSeg.end = p; 
                } else { 
                    obj.tracedSegments.push({ start: p, end: p }); 
                }
            } else if (obj.startHit) {
                // 페널티 가중치 완화: 120ms -> 200ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 85% 이상 AND 시작 터치가 PERFECT였음 AND 시작을 놓치지 않음
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                // 시작을 놓쳤거나 완벽하지 않아도 어느 정도 유지했다면 GOOD
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                // 유지율이 너무 낮으면 MISS
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', 0xe5e5e5, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xffffff, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정 (무작위 크기에 따른 가변 범위 적용)
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 55;
          if (obj.ringType === 'NARROW') tapHitRadius = 35;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 55;
          else if (obj.ringType === 'WIDE') tapHitRadius = 80;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            // 시작 링 타입에 따른 가변 판정 범위 설정
            let hitRadius = 55;
            if (obj.ringType === 'NARROW') hitRadius = 35;
            else if (obj.ringType === 'MEDIUM') hitRadius = 55;
            else if (obj.ringType === 'WIDE') hitRadius = 80;

            // 시작 지점 타이밍 오차 범위 내 터치 시
            if (d < hitRadius * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;

                // 링 타입별 정밀도 보정
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.06 : 0.04;
                obj.startHitPerfect = diff < perfectThreshold; 

                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];

                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                // PERFECT가 아닐 경우 링 고유 색상 적용, PERFECT일 경우 골드 적용
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;

    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);

            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }

            // 시작 지점 가이드 링 (유형별 색상 및 크기 적용)
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20;
                let strokeW = 4;
                let alpha = 1;

                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }

                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }

            // 종료 지점 가이드 링
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const steps = 60; const stepSize = (endP - startP) / steps;
    const firstPos = this.getPathPosition(startP); graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { const pos = this.getPathPosition(startP + stepSize * i); graphics.lineTo(pos.x, pos.y); }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    // 탭 페이즈(1, 3)의 노드들을 3가지 크기로 무작위 설정
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);

    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3)
        .setStrokeStyle(3, ringColor)
        .setDepth(8);

    this.interactables.push({ 
        type: 'TAP', p, hit: false, missed: false, 
        dragSuccessTicks: 0, totalTicksInRange: 0, 
        graphic: node,
        ringType 
    });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    // 드래그 페이즈(2, 4)의 시작점은 중간 크기로 고정
    const ringType: RingType = 'MEDIUM';

    this.interactables.push({ 
        type: 'DRAG', p: start, endP: end, hit: false, missed: false, 
        dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], 
        startHit: false, startHitPerfect: false, missedStart: false,
        ringType 
    });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);

        // 리사이즈 시 반경 업데이트
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;

    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          // 판정 지점 통과 체크
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  // 드래그 시작 터치를 놓친 경우: 즉시 실패 처리하지 않고 플래그만 설정
                  obj.missedStart = true;
              }
          }
      }
    });

    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();

    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 완화: 55 -> 80
            if (pointer.isDown && dist < 80 * this.uiScale) {
                // 시작 터치를 놓쳤더라도 중간에 잡으면 추적 시작
                if (!obj.startHit) {
                    obj.startHit = true;
                    // 중간에 잡은 경우 해당 지점부터 추적 시작
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }

                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);

                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { 
                    lastSeg.end = p; 
                } else { 
                    obj.tracedSegments.push({ start: p, end: p }); 
                }
            } else if (obj.startHit) {
                // 페널티 가중치 완화: 120ms -> 200ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else {
                this.cursor.clearTint();
            }
        }

        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 조건: 유지율 85% 이상 AND 시작 터치가 PERFECT였음 AND 시작을 놓치지 않음
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                // 시작을 놓쳤거나 완벽하지 않아도 어느 정도 유지했다면 GOOD
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else {
                // 유지율이 너무 낮으면 MISS
                obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y);
            }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      const ringColor = this.getRingColor(obj.ringType);

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00008; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.cursorSpeed = 0.00010 + data.difficulty * 0.000015; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 55;
          if (obj.ringType === 'NARROW') tapHitRadius = 35;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 55;
          else if (obj.ringType === 'WIDE') tapHitRadius = 80;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 55;
            if (obj.ringType === 'NARROW') hitRadius = 35;
            else if (obj.ringType === 'MEDIUM') hitRadius = 55;
            else if (obj.ringType === 'WIDE') hitRadius = 80;

            if (d < hitRadius * this.uiScale && diff < 0.1) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.06 : 0.04;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  /**
   * 고정된 조각 수가 아닌 고정된 거리(Distance) 기준으로 선을 렌더링하여
   * 진행 상황에 따라 선이 늘어나거나 꿈틀거리는 현상을 방지합니다.
   */
  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);

    // 조각 간의 거리를 픽셀 단위로 고정 (약 4px 간격)
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;

    // 전체 길이에 따른 조각 수 동적 계산 (최소 2개)
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;

    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);

    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);
            if (pointer.isDown && dist < 80 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 200) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.0);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.85 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.45) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);
    if (diff < 0.1) {
      obj.hit = true;
      const isPerfect = diff < 0.05;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; // 기본 속도 상향 (0.00008 -> 0.00012)
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private difficulty: number = 1;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    // 난이도 계수 상향 (0.000015 -> 0.000020)
    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        // TAP 판정 (판정 범위 대폭 축소)
        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        // DRAG 시작 터치 판정 (범위 축소 및 시작 타이밍 강화)
        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            // 시작 타이밍 오차 범위 축소: 0.1 -> 0.08
            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;

                // 시작 퍼펙트 타이밍 오차 축소
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 

                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);

                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.spawnInteractablesForPhase();
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;
    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            // 드래그 유지 판정 범위 축소: 80 -> 60
            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                // 페널티 가중치 강화: 200ms -> 150ms
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            // PERFECT 유지율 상향: 85% -> 92%
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) { // GOOD 유지율 상향: 45% -> 60%
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    // 탭 판정 타이밍 임계값 축소: 0.1 -> 0.07
    if (diff < 0.07) {
      obj.hit = true;
      // 퍼펙트 타이밍 축소: 0.05 -> 0.03
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5); // 감점 강화
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6); // 감점 상향
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별 (Chestplate, Gloves, Boots 등)
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('axe', getAssetUrl('axe.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도끼/톱 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 도끼
            this.cursor.setTexture('axe').setOrigin(0.5, 0.85).setScale(0.5);
        } else {
            // 가공 페이즈: 톱
            this.cursor.setTexture('saw').setOrigin(0.5, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정 (톱이나 도끼의 경우 바늘과 회전축이 다를 수 있음)
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별 (Chestplate, Gloves, Boots 등)
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 해머/톱 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 해머 (도끼에서 변경)
            this.cursor.setTexture('hammer').setOrigin(0.5, 0.8).setScale(0.45);
        } else {
            // 가공 페이즈: 톱
            this.cursor.setTexture('saw').setOrigin(0.5, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정 (톱이나 해머의 경우 바늘과 회전축이 다를 수 있음)
    const targetRotation = pos.angle - Math.PI / 2;
    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 해머/톱 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 해머
            this.cursor.setTexture('hammer').setOrigin(0.5, 0.8).setScale(0.45);
        } else {
            // 가공 페이즈: 톱 (D자 형태, 왼쪽이 날, 오른쪽이 손잡이)
            // 날이 경로를 타고 손잡이가 바깥으로 빠지도록 원점을 왼쪽 끝으로 설정
            this.cursor.setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);

    // 톱은 경로와 평행하게(0도 오프셋), 바늘/해머는 수직으로(-90도 오프셋)
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 못(Nail)/톱(Saw) 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 (Nail) - 끝부분이 경로에 닿도록 원점 조정
            this.cursor.setTexture('nail').setOrigin(0.5, 0.9).setScale(0.4);
        } else {
            // 가공 페이즈: 톱 (D자 형태, 왼쪽이 날, 오른쪽이 손잡이)
            this.cursor.setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => obj.graphic?.destroy());
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;
    const node = this.add.circle(0, 0, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);
    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      if (obj.type === 'TAP' && obj.graphic && !obj.hit && !obj.missed) {
        const pos = this.getPathPosition(obj.p);
        obj.graphic.setPosition(pos.x, pos.y);
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;
        obj.graphic.setRadius(ringRadius * this.uiScale);
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);

    // 톱은 경로와 평행하게(0도 오프셋), 바늘/못은 수직으로(-90도 오프셋)
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);
      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }
      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);
    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 못(Nail)/톱(Saw) 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 (Nail)
            this.cursor.setTexture('nail').setOrigin(0.5, 0.9).setScale(0.4);
        } else {
            // 가공 페이즈: 톱
            this.cursor.setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 이미지의 원본 크기가 대략 100x100이라고 가정할 때 반지름 * 2 만큼 채우도록 스케일링
        const baseScale = (ringRadius * 2) / 64; // 64는 nail_head 에셋의 예상 베이스 크기
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setScale(baseScale * this.uiScale);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const baseScale = (ringRadius * 2) / 64;
            obj.nailHead.setPosition(pos.x, pos.y).setScale(baseScale * this.uiScale * (obj.hit ? 0.8 : 1));
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 못 머리 타격 애니메이션 (0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              scale: obj.nailHead.scale * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 못(Nail)/톱(Saw) 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 (Nail)
            this.cursor.setTexture('nail').setOrigin(0.5, 0.9).setScale(0.4);
        } else {
            // 가공 페이즈: 톱
            this.cursor.setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
      this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); this.updateProgressBar();
      if (this.currentPhase < 4) this.startPhase(this.currentPhase + 1); else this.win();
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Image;
  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 초기 커서 생성
    this.cursor = this.add.image(0, 0, 'niddle').setDepth(10).setOrigin(0.5, 0.98).setScale(0.4);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 사용
        this.cursor.setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 못(Nail)/톱(Saw) 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 (Nail)
            this.cursor.setTexture('nail').setOrigin(0.5, 0.9).setScale(0.4);
        } else {
            // 가공 페이즈: 톱
            this.cursor.setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; this.cursor.setTint(0xfbbf24); 
                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; this.cursor.clearTint();
                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { this.cursor.clearTint(); }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) this.cursor.clearTint();
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 1.5초 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);

    // 망치 스프라이트 (헤드가 위, 손잡이가 아래이므로 원점을 하단으로 잡음)
    this.hammerSprite = this.add.image(0, -40, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0);

    this.cursor.add([this.cursorBar, this.cursorSprite, this.hammerSprite]);
    this.root.add(this.cursor);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    // 망치는 타격 시에만 보이게 관리하므로 기본적으로 숨김
    this.hammerSprite.setAlpha(0);

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 망치 타격 애니메이션 추가
      if (!this.isLeatherWork) {
          this.hammerSprite.setAlpha(1).setAngle(-45).setY(-40);
          this.tweens.chain({
              targets: this.hammerSprite,
              tweens: [
                  { angle: 0, y: -10, duration: 80, ease: 'Cubic.in' },
                  { angle: -15, y: -25, duration: 100, ease: 'Cubic.out' },
                  { alpha: 0, duration: 200 }
              ]
          });
      }

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    // 망치 스프라이트 (루트 컨테이너에 추가하여 커서 이동에 독립적으로 애니메이션 가능하게 함)
    this.hammerSprite = this.add.image(0, 0, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0).setDepth(25);
    this.root.add(this.hammerSprite);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i, nodePos.x, nodePos.y);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    // 망치는 타격 시에만 보이게 관리하므로 기본적으로 숨김
    this.hammerSprite.setAlpha(0);

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 망치 타격 애니메이션 (날아와서 때리는 모션, 5도 -> -30도)
      if (!this.isLeatherWork) {
          // 시작 위치: 타겟 위치에서 약간 떨어진 상단
          this.hammerSprite
              .setAlpha(1)
              .setPosition(targetX + 40, targetY - 60)
              .setAngle(5);

          this.tweens.add({
              targets: this.hammerSprite,
              x: targetX,
              y: targetY + 15, // 망치 헤드가 못 머리에 닿도록 약간 보정
              angle: -30,
              duration: 100,
              ease: 'Cubic.in',
              onComplete: () => {
                  // 타격 후 살짝 반동하며 사라짐
                  this.tweens.add({
                      targets: this.hammerSprite,
                      angle: -10,
                      y: targetY,
                      alpha: 0,
                      duration: 250,
                      ease: 'Cubic.out'
                  });
              }
          });
      }

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    // 망치 스프라이트 (루트 컨테이너에 추가하여 커서 이동에 독립적으로 애니메이션 가능하게 함)
    this.hammerSprite = this.add.image(0, 0, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0).setDepth(25);
    this.root.add(this.hammerSprite);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i, nodePos.x, nodePos.y);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    // 망치는 타격 시에만 보이게 관리하므로 기본적으로 숨김
    this.hammerSprite.setAlpha(0);

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 망치 타격 애니메이션 (날아와서 때리는 모션, 5도 -> -30도)
      if (!this.isLeatherWork) {
          // 시작 위치: 타겟 위치에서 상단으로 120px 오프셋 (Y축을 더 올림)
          this.hammerSprite
              .setAlpha(1)
              .setPosition(targetX + 40, targetY - 120)
              .setAngle(5);

          this.tweens.add({
              targets: this.hammerSprite,
              x: targetX,
              y: targetY - 5, // 망치 헤드가 못 머리 상단에 닿도록 보정 (상향 조정)
              angle: -30,
              duration: 100,
              ease: 'Cubic.in',
              onComplete: () => {
                  // 타격 후 살짝 반동하며 사라짐
                  this.tweens.add({
                      targets: this.hammerSprite,
                      angle: -10,
                      y: targetY - 15,
                      alpha: 0,
                      duration: 250,
                      ease: 'Cubic.out'
                  });
              }
          });
      }

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

interface Point {
  x: number;
  y: number;
}

type RingType = 'NARROW' | 'MEDIUM' | 'WIDE';

interface Interactable {
  type: 'TAP' | 'DRAG';
  p: number;        // 시작 지점 (0~1)
  endP?: number;    // 드래그 종료 지점
  hit: boolean;
  missed: boolean;
  dragSuccessTicks: number; // 드래그 유지 시간 측정
  totalTicksInRange: number; // 구간 내 총 체류 시간
  graphic?: Phaser.GameObjects.Arc; // TAP 전용 그래픽 참조
  nailHead?: Phaser.GameObjects.Image; // TAP 전용 못 머리 이미지
  tracedSegments?: { start: number; end: number }[]; // 실제로 터치하여 통과한 구간들
  startHit?: boolean; // 드래그 시작 터치 성공 여부
  startHitPerfect?: boolean; // 시작 터치가 퍼펙트였는지 여부
  missedStart?: boolean; // 시작 지점 터치 타이밍을 완전히 놓쳤는지 여부
  ringType?: RingType;   // 드래그 시작 링 또는 탭 노드의 크기 유형
}

/**
 * Ramer-Douglas-Peucker 단순화용 수직 거리 계산
 */
function findPerpendicularDistance(p: Point, p1: Point, p2: Point) {
  if (p1.x === p2.x) return Math.abs(p.x - p1.x);
  const slope = (p2.y - p1.y) / (p2.x - p1.x);
  const intercept = p1.y - slope * p1.x;
  return Math.abs(slope * p.x - p.y + intercept) / Math.sqrt(Math.pow(slope, 2) + 1);
}

/**
 * Ramer-Douglas-Peucker 알고리즘
 */
function rdp(points: Point[], epsilon: number): Point[] {
  if (points.length < 3) return points;
  let dmax = 0;
  let index = 0;
  for (let i = 1; i < points.length - 1; i++) {
    const d = findPerpendicularDistance(points[i], points[0], points[points.length - 1]);
    if (d > dmax) {
      index = i;
      dmax = d;
    }
  }
  if (dmax > epsilon) {
    const res1 = rdp(points.slice(0, index + 1), epsilon);
    const res2 = rdp(points.slice(index), epsilon);
    return [...res1.slice(0, res1.length - 1), ...res2];
  }
  return [points[0], points[points.length - 1]];
}

export default class WorkbenchScene extends Phaser.Scene {
  public add!: Phaser.GameObjects.GameObjectFactory;
  public tweens!: Phaser.Tweens.TweenManager;
  public scale!: Phaser.Scale.ScaleManager;
  public input!: Phaser.Input.InputPlugin;
  public time!: Phaser.Time.Clock;
  public load!: Phaser.Loader.LoaderPlugin;
  public textures!: Phaser.Textures.TextureManager;
  public events!: Phaser.Events.EventEmitter;
  public cameras!: Phaser.Cameras.Scene2D.CameraManager;

  private interactables: Interactable[] = [];

  private cursor!: Phaser.GameObjects.Container;
  private cursorSprite!: Phaser.GameObjects.Image;
  private cursorBar!: Phaser.GameObjects.Rectangle;
  private hammerSprite!: Phaser.GameObjects.Image;

  private comboText!: Phaser.GameObjects.Text;
  private progBg!: Phaser.GameObjects.Rectangle;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private qualityText!: Phaser.GameObjects.Text;
  private pathGraphics!: Phaser.GameObjects.Graphics;
  private dragPathGraphics!: Phaser.GameObjects.Graphics;
  private silhouetteGraphics!: Phaser.GameObjects.Graphics;
  private itemSprite!: Phaser.GameObjects.Image;
  private bgImage!: Phaser.GameObjects.Image;
  private root!: Phaser.GameObjects.Container;

  private cursorProgress = 0;
  private cursorSpeed = 0.00012; 
  private confirmedProgress = 0;
  private currentQuality = 100;
  private combo = 0;
  private isFinished = false;
  private isTransitioning = false; // 페이즈 간 대기 상태 플래그
  private currentPhase = 1;

  private onComplete?: (score: number, bonus?: number) => void;
  private itemImage: string = '';
  private subCategoryId: string = '';
  private difficulty: number = 1;
  private isLeatherWork: boolean = false;

  private centerX = 0;
  private centerY = 0;
  private viewW = 0;
  private viewH = 0;
  private uiScale = 1;

  private itemInternalData = {
    points: [] as Point[],
    width: 0,
    height: 0,
    centerX: 0,
    centerY: 0,
    texW: 0,
    texH: 0
  };

  private worldPoints: Phaser.Math.Vector2[] = [];
  private cumulativeLengths: number[] = [];
  private totalPathLength = 0;

  private dragPenaltyTimer = 0;

  constructor() {
    super('WorkbenchScene');
  }

  init(data: { onComplete: (score: number, bonus?: number) => void; difficulty: number; subCategoryId?: string; itemImage?: string }) {
    this.onComplete = data.onComplete;
    this.difficulty = data.difficulty;
    this.itemImage = data.itemImage || '';
    this.subCategoryId = data.subCategoryId || '';

    // 가죽 아이템 여부 판별
    const leatherCategories = ['CHESTPLATE', 'GLOVES', 'BOOTS'];
    this.isLeatherWork = leatherCategories.includes(this.subCategoryId.toUpperCase());

    this.cursorSpeed = 0.00012 + data.difficulty * 0.000020; 
    this.isFinished = false;
    this.isTransitioning = false;
    this.cursorProgress = 0;
    this.confirmedProgress = 0;
    this.currentQuality = 100;
    this.combo = 0;
    this.currentPhase = 1;
    this.interactables = [];
  }

  preload() {
    this.load.image('workbench_bg', getAssetUrl('workbench_bg.png'));
    this.load.image('niddle', getAssetUrl('niddle.png'));
    this.load.image('nail', getAssetUrl('nail.png'));
    this.load.image('nail_head', getAssetUrl('nail_head.png'));
    this.load.image('hammer', getAssetUrl('hammer.png'));
    this.load.image('saw', getAssetUrl('saw.png'));
    this.load.image('spark', getAssetUrl('particle_spark1.png'));
    if (this.itemImage) {
        this.load.image('item_source', getAssetUrl(this.itemImage));
    }
  }

  private getRingColor(type?: RingType): number {
    if (type === 'NARROW') return 0x22d3ee; // Cyan
    if (type === 'WIDE') return 0xa855f7;   // Violet
    return 0x10b981;                        // Emerald (Medium)
  }

  create() {
    this.root = this.add.container(0, 0);

    this.bgImage = this.add.image(0, 0, 'workbench_bg').setAlpha(0.6).setOrigin(0.5);
    this.root.add(this.bgImage);

    this.silhouetteGraphics = this.add.graphics().setAlpha(0.2);
    this.root.add(this.silhouetteGraphics);

    if (this.textures.exists('item_source')) {
      this.itemSprite = this.add.image(0, 0, 'item_source').setAlpha(0.15);
      this.root.add(this.itemSprite);
    }

    this.pathGraphics = this.add.graphics();
    this.dragPathGraphics = this.add.graphics();
    this.root.add([this.pathGraphics, this.dragPathGraphics]);

    this.progBg = this.add.rectangle(0, 0, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e);
    this.progressBar = this.add.rectangle(0, 0, 0.1, 12, 0x10b981).setOrigin(0, 0.5);
    this.qualityText = this.add.text(0, 0, 'PRISTINE', { fontFamily: 'Grenze Gotisch', fontSize: '20px', color: '#fbbf24', fontStyle: 'bold' }).setOrigin(0.5);
    this.root.add([this.progBg, this.progressBar, this.qualityText]);

    // 커서 컨테이너 및 도구들 초기화
    this.cursor = this.add.container(0, 0).setDepth(10);
    this.cursorSprite = this.add.image(0, 0, 'niddle').setOrigin(0.5, 0.98).setScale(0.4);
    this.cursorBar = this.add.rectangle(0, 0, 6, 40, 0xfbbf24).setOrigin(0.5, 1).setStrokeStyle(2, 0xffffff, 0.8);
    this.cursor.add([this.cursorBar, this.cursorSprite]);
    this.root.add(this.cursor);

    // 망치 스프라이트 (루트 컨테이너에 추가하여 커서 이동에 독립적으로 애니메이션 가능하게 함)
    this.hammerSprite = this.add.image(0, 0, 'hammer').setOrigin(0.5, 0.9).setScale(0.35).setAlpha(0).setDepth(25);
    this.root.add(this.hammerSprite);

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Grenze Gotisch', fontSize: '42px', color: '#fcd34d', stroke: '#000', strokeThickness: 6 }).setOrigin(0.5).setAlpha(0).setDepth(20);
    this.root.add(this.comboText);

    this.generatePathFromTexture();
    this.handleResize(this.scale.gameSize);
    this.scale.on('resize', this.handleResize, this);

    this.input.on('pointerdown', (p: Phaser.Input.Pointer) => {
      if (this.isFinished || this.isTransitioning) return;

      for (let i = 0; i < this.interactables.length; i++) {
        const obj = this.interactables[i];
        const nodePos = this.getPathPosition(obj.p);
        const d = Phaser.Math.Distance.Between(p.x, p.y, nodePos.x, nodePos.y);
        const diff = Math.abs(this.cursorProgress - obj.p);

        if (obj.type === 'TAP' && !obj.hit && !obj.missed) {
          let tapHitRadius = 42; 
          if (obj.ringType === 'NARROW') tapHitRadius = 26;
          else if (obj.ringType === 'MEDIUM') tapHitRadius = 42;
          else if (obj.ringType === 'WIDE') tapHitRadius = 62;

          if (d < tapHitRadius * this.uiScale) {
            this.handleTapHit(i, nodePos.x, nodePos.y);
            break;
          }
        }

        if (obj.type === 'DRAG' && !obj.hit && !obj.missed && !obj.startHit) {
            let hitRadius = 42;
            if (obj.ringType === 'NARROW') hitRadius = 26;
            else if (obj.ringType === 'MEDIUM') hitRadius = 42;
            else if (obj.ringType === 'WIDE') hitRadius = 62;

            if (d < hitRadius * this.uiScale && diff < 0.08) {
                obj.startHit = true;
                obj.missedStart = false;
                const perfectThreshold = obj.ringType === 'NARROW' ? 0.025 : 0.035;
                obj.startHitPerfect = diff < perfectThreshold; 
                obj.tracedSegments = [{ start: obj.p, end: this.cursorProgress }];
                const label = obj.startHitPerfect ? 'PERFECT!' : 'GOOD';
                const color = obj.startHitPerfect ? 0xfbbf24 : this.getRingColor(obj.ringType);
                this.showFeedback(label, color, nodePos.x, nodePos.y);
                this.createSparks(nodePos.x, nodePos.y, color, obj.startHitPerfect ? 10 : 5);
                break;
            }
        }
      }
    });

    this.startPhase(1);
  }

  private startPhase(phase: number) {
    this.currentPhase = phase;
    this.cursorProgress = 0;
    this.isTransitioning = false;
    this.updateCursorTool();
    this.spawnInteractablesForPhase();

    // 커서를 경로의 시작점으로 즉시 이동
    const pos = this.getPathPosition(0);
    this.cursor.setPosition(pos.x, pos.y);
  }

  private updateCursorTool() {
    if (!this.cursor) return;

    // 망치는 타격 시에만 보이게 관리하므로 기본적으로 숨김
    this.hammerSprite.setAlpha(0);

    if (this.isLeatherWork) {
        // 가죽 작업일 경우 항상 바늘 이미지 사용
        this.cursorSprite.setVisible(true).setTexture('niddle').setOrigin(0.5, 0.98).setScale(0.4);
        this.cursorBar.setVisible(false);
    } else {
        // 가죽이 아닐 경우 페이즈에 따라 도구 전환
        if (this.currentPhase === 1 || this.currentPhase === 3) {
            // 타격 페이즈: 못 대신 직사각형 막대 사용
            this.cursorSprite.setVisible(false);
            this.cursorBar.setVisible(true).setFillStyle(0xfbbf24).setAlpha(1);
        } else {
            // 가공 페이즈: 톱 이미지 사용
            this.cursorSprite.setVisible(true).setTexture('saw').setOrigin(0.05, 0.5).setScale(0.45);
            this.cursorBar.setVisible(false);
        }
    }
  }

  private generatePathFromTexture() {
    const key = 'item_source';
    if (!this.textures.exists(key)) return;
    const texture = this.textures.get(key).getSourceImage() as HTMLImageElement;
    const canvas = document.createElement('canvas');
    canvas.width = texture.width; canvas.height = texture.height;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;
    ctx.drawImage(texture, 0, 0);
    const imgData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imgData.data; const w = canvas.width; const h = canvas.height;
    const isOpaque = (x: number, y: number) => {
        if (x < 0 || x >= w || y < 0 || y >= h) return false;
        return data[(y * w + x) * 4 + 3] > 50;
    };
    let startPoint: Point | null = null;
    outer: for (let y = 0; y < h; y++) {
        for (let x = 0; x < w; x++) { if (isOpaque(x, y)) { startPoint = { x, y }; break outer; } }
    }
    if (!startPoint) return;
    const path: Point[] = []; let curr = { ...startPoint }; let prev = { x: startPoint.x, y: startPoint.y - 1 };
    const neighbors = [{x:-1, y:-1}, {x:0, y:-1}, {x:1, y:-1}, {x:1, y:0}, {x:1, y:1}, {x:0, y:1}, {x:-1, y:1}, {x:-1, y:0}];
    let iters = 0;
    while (iters < w * h) {
        const relX = prev.x - curr.x; const relY = prev.y - curr.y;
        let startIdx = neighbors.findIndex(n => n.x === relX && n.y === relY);
        if (startIdx === -1) startIdx = 0;
        let found = false;
        for (let i = 1; i <= 8; i++) {
            const idx = (startIdx + i) % 8; const nx = curr.x + neighbors[idx].x; const ny = curr.y + neighbors[idx].y;
            if (isOpaque(nx, ny)) { prev = { ...curr }; curr = { x: nx, y: ny }; path.push({ ...curr }); found = true; break; }
        }
        if (!found || (curr.x === startPoint.x && curr.y === startPoint.y)) break;
        iters++;
    }
    const simplified = rdp(path, 1.5);
    let minX = w, maxX = 0, minY = h, maxY = 0;
    simplified.forEach(p => {
        if (p.x < minX) minX = p.x; if (p.x > maxX) maxX = p.x;
        if (p.y < minY) minY = p.y; if (p.y > maxY) maxY = p.y;
    });
    const itemW = maxX - minX || 1; const itemH = maxY - minY || 1;
    const itemCX = (minX + maxX) / 2; const itemCY = (minY + maxY) / 2;
    this.itemInternalData = { points: simplified.map(p => ({ x: p.x - itemCX, y: p.y - itemCY })), width: itemW, height: itemH, centerX: itemCX, centerY: itemCY, texW: w, texH: h };
  }

  private handleResize(gameSize?: Phaser.Structs.Size) {
    const w = gameSize?.width ?? this.scale.width;
    const h = gameSize?.height ?? this.scale.height;
    if (w <= 0 || h <= 0) return;
    this.viewW = w; this.viewH = h; this.centerX = w / 2; this.centerY = h / 2;
    const isPortrait = h > w;
    this.uiScale = isPortrait ? Phaser.Math.Clamp(w / 400, 0.7, 1) : Phaser.Math.Clamp(h / 600, 0.8, 1.2);
    this.bgImage.setPosition(this.centerX, this.centerY).setDisplaySize(Math.max(w, h * 1.5), Math.max(h, w / 1.5));
    const pbY = isPortrait ? 80 : 40;
    this.progBg.setPosition(this.centerX, pbY * this.uiScale).setSize(Math.min(w * 0.7, 400), 18 * this.uiScale);
    this.progressBar.setPosition(this.progBg.x - this.progBg.width / 2, this.progBg.y);
    this.qualityText.setPosition(this.centerX, (pbY + 35) * this.uiScale);
    this.recalculateWorldPath();
    this.drawGuidePath();
    this.updateInteractablesVisuals();
    this.updateProgressBar();
  }

  private recalculateWorldPath() {
    if (this.itemInternalData.points.length === 0) return;
    const isPortrait = this.viewH > this.viewW;
    const maxAreaW = this.viewW * (isPortrait ? 0.85 : 0.65);
    const maxAreaH = this.viewH * (isPortrait ? 0.45 : 0.6);
    const scale = Math.min(maxAreaW / this.itemInternalData.width, maxAreaH / this.itemInternalData.height);
    this.worldPoints = this.itemInternalData.points.map(p => new Phaser.Math.Vector2(this.centerX + (p.x * scale), this.centerY + (p.y * scale)));
    if (this.itemSprite) {
        this.itemSprite.setPosition(this.centerX, this.centerY).setScale(scale).setOrigin(this.itemInternalData.centerX / this.itemInternalData.texW, this.itemInternalData.centerY / this.itemInternalData.texH);
    }
    this.cumulativeLengths = [0]; let total = 0;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      total += Phaser.Math.Distance.BetweenPoints(this.worldPoints[i], this.worldPoints[i+1]);
      this.cumulativeLengths.push(total);
    }
    this.totalPathLength = total;
  }

  private drawGuidePath(time: number = 0) {
    this.silhouetteGraphics.clear(); this.pathGraphics.clear(); this.dragPathGraphics.clear();
    if (this.worldPoints.length < 2) return;
    this.silhouetteGraphics.fillStyle(0x1a0b08, 1).beginPath().moveTo(this.worldPoints[0].x, this.worldPoints[0].y);
    for (let i = 1; i < this.worldPoints.length; i++) this.silhouetteGraphics.lineTo(this.worldPoints[i].x, this.worldPoints[i].y);
    this.silhouetteGraphics.closePath().fillPath();
    this.pathGraphics.lineStyle(3, 0xfde68a, 0.4);
    const dashSize = 10, gapSize = 8;
    for (let i = 0; i < this.worldPoints.length - 1; i++) {
      const start = this.worldPoints[i], end = this.worldPoints[i+1];
      const dist = Phaser.Math.Distance.BetweenPoints(start, end), angle = Phaser.Math.Angle.BetweenPoints(start, end);
      let currentDist = 0, draw = true;
      while (currentDist < dist) {
        const step = draw ? dashSize : gapSize; const nextDist = Math.min(currentDist + step, dist);
        if (draw) this.pathGraphics.lineBetween(start.x + Math.cos(angle) * currentDist, start.y + Math.sin(angle) * currentDist, start.x + Math.cos(angle) * nextDist, start.y + Math.sin(angle) * nextDist);
        currentDist = nextDist; draw = !draw;
      }
    }
    this.interactables.forEach(obj => {
        if (obj.type === 'DRAG' && obj.endP && !obj.missed) {
            this.drawPathSegment(obj.p, obj.endP, this.dragPathGraphics, 0x10b981, 0.4, 5);
            if (obj.tracedSegments) {
                obj.tracedSegments.forEach(seg => {
                    this.drawPathSegment(seg.start, seg.end, this.dragPathGraphics, 0xfbbf24, 1.0, 8);
                });
            }
            if (!obj.startHit && !obj.hit) {
                const startPos = this.getPathPosition(obj.p);
                const ringColor = this.getRingColor(obj.ringType);
                let ringRadius = 20; let strokeW = 4; let alpha = 1;
                if (obj.ringType === 'NARROW') { ringRadius = 12; strokeW = 5; alpha = 1.0; }
                else if (obj.ringType === 'MEDIUM') { ringRadius = 20; strokeW = 4; alpha = 0.8; }
                else if (obj.ringType === 'WIDE') { ringRadius = 30; strokeW = 3; alpha = 0.6; }
                this.dragPathGraphics.lineStyle(strokeW, ringColor, alpha).strokeCircle(startPos.x, startPos.y, ringRadius * this.uiScale);
                this.dragPathGraphics.fillStyle(ringColor, alpha * 0.4).fillCircle(startPos.x, startPos.y, (ringRadius - 6) * this.uiScale);
            }
            const endPos = this.getPathPosition(obj.endP);
            this.dragPathGraphics.lineStyle(4, 0xfbbf24, 1).strokeCircle(endPos.x, endPos.y, 14 * this.uiScale);
            this.dragPathGraphics.fillStyle(0xfbbf24, 0.5).fillCircle(endPos.x, endPos.y, 8 * this.uiScale);
        }
    });
  }

  private drawPathSegment(startP: number, endP: number, graphics: Phaser.GameObjects.Graphics, color: number, alpha: number, width: number) {
    graphics.lineStyle(width, color, alpha);
    const stepDistancePx = 4;
    const segmentLengthP = endP - startP;
    const segmentLengthPx = segmentLengthP * this.totalPathLength;
    const steps = Math.max(2, Math.ceil(segmentLengthPx / stepDistancePx));
    const stepSizeP = segmentLengthP / steps;
    const firstPos = this.getPathPosition(startP); 
    graphics.beginPath().moveTo(firstPos.x, firstPos.y);
    for (let i = 1; i <= steps; i++) { 
        const currentP = startP + stepSizeP * i;
        const pos = this.getPathPosition(currentP); 
        graphics.lineTo(pos.x, pos.y); 
    }
    graphics.strokePath();
  }

  private getPathPosition(p: number): { x: number; y: number; angle: number } {
    const normalizedP = p < 0 ? 1 + (p % 1) : p % 1;
    const targetLen = normalizedP * this.totalPathLength;
    let seg = 0; while (seg < this.cumulativeLengths.length - 2 && this.cumulativeLengths[seg + 1] < targetLen) seg++;
    const segStart = this.cumulativeLengths[seg], segEnd = this.cumulativeLengths[seg + 1];
    const t = (targetLen - segStart) / (segEnd - segStart || 1);
    const p1 = this.worldPoints[seg], p2 = this.worldPoints[seg + 1];
    return { x: Phaser.Math.Linear(p1.x, p2.x, t), y: Phaser.Math.Linear(p1.y, p2.y, t), angle: Phaser.Math.Angle.BetweenPoints(p1, p2) };
  }

  private spawnInteractablesForPhase() {
    this.interactables.forEach(obj => {
        obj.graphic?.destroy();
        obj.nailHead?.destroy();
    });
    this.interactables = [];
    if (this.currentPhase === 1 || this.currentPhase === 3) {
        const count = this.currentPhase === 1 ? 4 : 8;
        for (let i = 0; i < count; i++) {
            const sectorWidth = 1.0 / count;
            const randomP = (i * sectorWidth) + Phaser.Math.FloatBetween(sectorWidth * 0.2, sectorWidth * 0.8);
            this.addTap(randomP % 1.0);
        }
    } else {
        const start = Phaser.Math.FloatBetween(0.02, 0.15);
        const length = Phaser.Math.FloatBetween(0.75, 0.85);
        this.addDrag(start, start + length);
    }
    this.updateInteractablesVisuals();
    this.drawGuidePath();
  }

  private addTap(p: number) {
    const types: RingType[] = ['NARROW', 'MEDIUM', 'WIDE'];
    const ringType = types[Math.floor(Math.random() * types.length)];
    const ringColor = this.getRingColor(ringType);
    let ringRadius = 20;
    if (ringType === 'NARROW') ringRadius = 12;
    else if (ringType === 'MEDIUM') ringRadius = 20;
    else if (ringType === 'WIDE') ringRadius = 30;

    const pos = this.getPathPosition(p);
    const node = this.add.circle(pos.x, pos.y, ringRadius * this.uiScale, ringColor, 0.3).setStrokeStyle(3, ringColor).setDepth(8);

    // 못 머리 이미지 추가 (비가죽 작업 타격 페이즈 전용)
    let nailHead: Phaser.GameObjects.Image | undefined;
    if (!this.isLeatherWork) {
        // 못 머리 크기를 링의 지름(radius * 2)과 동일하게 설정
        const targetSize = ringRadius * 2 * this.uiScale;
        nailHead = this.add.image(pos.x, pos.y, 'nail_head').setDepth(7).setDisplaySize(targetSize, targetSize);
        this.root.add(nailHead);
    }

    this.interactables.push({ type: 'TAP', p, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, graphic: node, nailHead, ringType });
    this.root.add(node);
  }

  private addDrag(start: number, end: number) {
    const ringType: RingType = 'MEDIUM';
    this.interactables.push({ type: 'DRAG', p: start, endP: end, hit: false, missed: false, dragSuccessTicks: 0, totalTicksInRange: 0, tracedSegments: [], startHit: false, startHitPerfect: false, missedStart: false, ringType });
  }

  private updateInteractablesVisuals() {
    this.interactables.forEach((obj) => {
      const pos = this.getPathPosition(obj.p);
      if (obj.type === 'TAP' && !obj.missed) {
        let ringRadius = 20;
        if (obj.ringType === 'NARROW') ringRadius = 12;
        else if (obj.ringType === 'MEDIUM') ringRadius = 20;
        else if (obj.ringType === 'WIDE') ringRadius = 30;

        if (obj.graphic) {
            obj.graphic.setPosition(pos.x, pos.y).setRadius(ringRadius * this.uiScale);
        }
        if (obj.nailHead) {
            const targetSize = ringRadius * 2 * this.uiScale;
            // 지름에 맞춰서 크기 조정 (히트 시에는 0.8배 축소된 상태 유지)
            const finalSize = targetSize * (obj.hit ? 0.8 : 1);
            obj.nailHead.setPosition(pos.x, pos.y).setDisplaySize(finalSize, finalSize);
        }
      }
    });
  }

  update(time: number, delta: number) {
    if (this.isFinished || this.isTransitioning || this.worldPoints.length < 2) return;
    this.cursorProgress += this.cursorSpeed * delta;
    this.interactables.forEach((obj) => {
      if (!obj.hit && !obj.missed) {
          if (this.cursorProgress > obj.p + 0.1) {
              if (obj.type === 'TAP') {
                  obj.missed = true;
                  const pos = this.getPathPosition(obj.p);
                  this.handleMiss(pos.x, pos.y, obj);
              } else if (obj.type === 'DRAG' && !obj.startHit && !obj.missedStart) {
                  obj.missedStart = true;
              }
          }
      }
    });
    this.handleDragLogic(time, delta);
    if (this.cursorProgress >= 1.0) this.finishPhase();
    const pos = this.getPathPosition(this.cursorProgress);
    this.cursor.setPosition(pos.x, pos.y);

    // 도구 회전 각도 보정
    const isSaw = !this.isLeatherWork && (this.currentPhase === 2 || this.currentPhase === 4);
    const rotationOffset = isSaw ? 0 : -Math.PI / 2;
    const targetRotation = pos.angle + rotationOffset;

    const angleDelta = Phaser.Math.Angle.ShortestBetween(Phaser.Math.RadToDeg(this.cursor.rotation), Phaser.Math.RadToDeg(targetRotation));
    this.cursor.angle += angleDelta * 0.15;

    this.qualityText.setText(this.getQualityLabel(this.currentQuality)).setColor(this.getLabelColor(this.currentQuality));
    if (this.itemSprite) this.itemSprite.setAlpha(0.15 + (this.confirmedProgress / 100) * 0.7);
    this.drawGuidePath(time);
  }

  private handleDragLogic(time: number, delta: number) {
    const p = this.cursorProgress;
    this.interactables.forEach(obj => {
      if (obj.type === 'DRAG' && !obj.hit && !obj.missed) {
        const inside = p >= obj.p && p <= obj.endP!;
        if (inside) {
            obj.totalTicksInRange += delta;
            const pointer = this.input.activePointer;
            const dist = Phaser.Math.Distance.Between(pointer.x, pointer.y, this.cursor.x, this.cursor.y);

            if (pointer.isDown && dist < 60 * this.uiScale) {
                if (!obj.startHit) {
                    obj.startHit = true;
                    if (!obj.tracedSegments) obj.tracedSegments = [];
                    obj.tracedSegments.push({ start: p, end: p });
                }
                obj.dragSuccessTicks += delta; 
                this.dragPenaltyTimer = 0; 
                if (this.cursorSprite.visible) this.cursorSprite.setTint(0xfbbf24);
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfcd34d);

                if (time % 100 < 20) this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 1);
                if (!obj.tracedSegments) obj.tracedSegments = [];
                const lastSeg = obj.tracedSegments[obj.tracedSegments.length - 1];
                if (lastSeg && Math.abs(lastSeg.end - p) < 0.05) { lastSeg.end = p; } 
                else { obj.tracedSegments.push({ start: p, end: p }); }
            } else if (obj.startHit) {
                this.dragPenaltyTimer += delta; 
                this.cursorSprite.clearTint();
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);

                if (this.dragPenaltyTimer > 150) {
                    this.dragPenaltyTimer = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.2);
                    this.combo = 0; this.createSparks(this.cursor.x, this.cursor.y, 0xef4444, 2); this.cameras.main.shake(40, 0.001);
                }
            } else { 
                this.cursorSprite.clearTint(); 
                if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
            }
        }
        if (p > obj.endP! + 0.02 && obj.totalTicksInRange > 50) {
            const ratio = obj.dragSuccessTicks / obj.totalTicksInRange;
            if (ratio > 0.92 && obj.startHitPerfect && !obj.missedStart) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 3.0);
                this.showFeedback('PERFECT!', 0xfbbf24, this.cursor.x, this.cursor.y); this.createSparks(this.cursor.x, this.cursor.y, 0xfbbf24, 15);
            } else if (ratio > 0.60) {
                obj.hit = true; this.currentQuality = Math.min(120, this.currentQuality + 1.0);
                this.showFeedback('GOOD', 0xe5e5e5, this.cursor.x, this.cursor.y);
            } else { obj.missed = true; this.handleMiss(this.cursor.x, this.cursor.y); }
        }
      }
    });
    if (!this.interactables.some(obj => obj.type === 'DRAG' && p >= obj.p && p <= obj.endP!)) {
        this.cursorSprite.clearTint();
        if (this.cursorBar.visible) this.cursorBar.setFillStyle(0xfbbf24);
    }
  }

  private handleTapHit(idx: number, targetX: number, targetY: number) {
    const obj = this.interactables[idx];
    const diff = Math.abs(this.cursorProgress - obj.p);
    const pos = this.getPathPosition(obj.p);

    if (diff < 0.07) {
      obj.hit = true;
      const isPerfect = diff < 0.03;
      const ringColor = this.getRingColor(obj.ringType);

      // 망치 타격 애니메이션 (날아와서 때리는 모션, 5도 -> -30도)
      if (!this.isLeatherWork) {
          // 시작 위치: 타겟 위치에서 상단으로 120px 오프셋 (Y축을 더 올림)
          this.hammerSprite
              .setAlpha(1)
              .setPosition(targetX + 40, targetY - 120)
              .setAngle(5);

          this.tweens.add({
              targets: this.hammerSprite,
              x: targetX,
              y: targetY + 20, // 망치 헤드가 못 머리 상단에 닿도록 보정 (앵커인 손잡이 부분을 타겟 중심 아래로 배치하여 헤드가 닿게 함)
              angle: -30,
              duration: 100,
              ease: 'Cubic.in',
              onComplete: () => {
                  // 타격 후 살짝 반동하며 사라짐
                  this.tweens.add({
                      targets: this.hammerSprite,
                      angle: -10,
                      y: targetY + 10,
                      alpha: 0,
                      duration: 250,
                      ease: 'Cubic.out'
                  });
              }
          });
      }

      // 못 머리 타격 애니메이션 (지름 기준 0.8배 축소)
      if (obj.nailHead) {
          this.tweens.add({
              targets: obj.nailHead,
              displayWidth: obj.nailHead.displayWidth * 0.8,
              displayHeight: obj.nailHead.displayHeight * 0.8,
              duration: 100,
              ease: 'Back.easeOut'
          });
      }

      if (isPerfect) {
        this.combo++; this.currentQuality = Math.min(120, this.currentQuality + 2);
        this.showFeedback('PERFECT!', 0xfbbf24, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, 0xfbbf24, 15);
      } else {
        this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 1.5);
        this.showFeedback('GOOD', ringColor, pos.x, pos.y);
        this.createSparks(pos.x, pos.y, ringColor, 8);
      }

      if (obj.graphic) {
          const target = obj.graphic;
          this.tweens.add({ targets: target, scale: this.uiScale * 2, alpha: 0, duration: 300, ease: 'Cubic.out', onComplete: () => target.destroy() });
      }
    }
  }

  private handleMiss(x: number, y: number, obj?: Interactable) {
    this.combo = 0; this.currentQuality = Math.max(0, this.currentQuality - 6);
    this.showFeedback('MISS', 0xef4444, x, y);
    this.createSparks(x, y, 0xef4444, 8); this.cameras.main.shake(120, 0.005);

    if (obj?.graphic) { this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 200, onComplete: () => obj.graphic?.destroy() }); }
    if (obj?.nailHead) { this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 200, onComplete: () => obj.nailHead?.destroy() }); }
  }

  private finishPhase() {
    this.isTransitioning = true; // 전환 상태 시작
    this.confirmedProgress = Math.min(100, this.confirmedProgress + 25); 
    this.updateProgressBar();

    // 현재 인터랙션 그래픽들 페이드 아웃
    this.interactables.forEach(obj => {
        if (obj.graphic) this.tweens.add({ targets: obj.graphic, alpha: 0, duration: 400 });
        if (obj.nailHead) this.tweens.add({ targets: obj.nailHead, alpha: 0, duration: 400 });
    });

    const isLastPhase = this.currentPhase >= 4;
    const splashText = isLastPhase ? 'WORK COMPLETE!' : `PHASE ${this.currentPhase} COMPLETE!`;
    const splashColor = isLastPhase ? '#fbbf24' : '#10b981';

    // 슬래시 텍스트 표시
    const splash = this.add.text(this.centerX, this.centerY, splashText, {
        fontFamily: 'Grenze Gotisch',
        fontSize: '48px',
        color: splashColor,
        stroke: '#000',
        strokeThickness: 8
    }).setOrigin(0.5).setAlpha(0).setScale(0.5).setDepth(100);

    this.root.add(splash);

    this.tweens.chain({
        targets: splash,
        tweens: [
            { alpha: 1, scale: 1.2, duration: 400, ease: 'Back.out' },
            { scale: 1, duration: 800 },
            { alpha: 0, scale: 1.5, duration: 300, ease: 'Cubic.in' }
        ],
        onComplete: () => {
            splash.destroy();
            if (isLastPhase) {
                this.win();
            } else {
                // 대기 후 다음 페이즈 시작
                this.time.delayedCall(500, () => {
                    this.startPhase(this.currentPhase + 1);
                });
            }
        }
    });
  }

  private updateProgressBar() { const w = (this.confirmedProgress / 100) * this.progBg.width; this.progressBar.width = Math.max(0.1, w); }

  private createSparks(x: number, y: number, color: number, count: number = 12) {
    const emitter = this.add.particles(x, y, 'spark', { lifespan: 500, speed: { min: 100, max: 250 }, scale: { start: 0.5, end: 0 }, alpha: { start: 1, end: 0 }, blendMode: 'ADD', tint: color, gravityY: 400 });
    this.root.add(emitter); emitter.explode(count);
    this.time.delayedCall(600, () => emitter.destroy());
  }

  private showFeedback(text: string, color: number, x: number, y: number) {
    const fb = this.add.text(x, y, text, { fontFamily: 'Grenze Gotisch', fontSize: `${Math.round(24 * this.uiScale)}px`, color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setDepth(30);
    this.root.add(fb); this.tweens.add({ targets: fb, y: y - 40, alpha: 0, duration: 600, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setPosition(x, y - 70).setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, alpha: 0, scale: 1.2, duration: 800 }); }
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return 'MASTERWORK'; if (q >= 100) return 'PRISTINE'; if (q >= 90) return 'SUPERIOR'; if (q >= 80) return 'FINE'; if (q >= 70) return 'STANDARD'; if (q >= 60) return 'RUSTIC'; return 'CRUDE';
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; if (q >= 100) return '#fbbf24'; if (q >= 90) return '#10b981'; if (q >= 80) return '#3b82f6'; if (q >= 70) return '#a8a29e'; if (q >= 60) return '#d97706'; return '#ef4444';
  }

  private win() {
    this.isFinished = true; this.cursor.setVisible(false);
    const mask = this.add.rectangle(this.centerX, this.centerY, this.viewW, this.viewH, 0x000000).setAlpha(0).setDepth(100);
    this.root.add(mask); this.tweens.add({ targets: mask, alpha: 0.7, duration: 400 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label}\nCRAFT!`, { fontFamily: 'Grenze Gotisch', fontSize: '48px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 6, align: 'center' }).setOrigin(0.5).setAlpha(0).setDepth(101).setScale(0.5);
    this.root.add(txt); this.tweens.add({ targets: txt, alpha: 1, scale: 1, duration: 600, ease: 'Back.out', onComplete: () => {
        this.time.delayedCall(1200, () => { if (this.onComplete) this.onComplete(this.currentQuality); });
    }});
  }
}
